INSERT INTO pc_site_profile (id, site_name, site_url, support_phone, support_label, max_widget_url, footer_blurb, home_content, legal_content, updated_at)
VALUES (1, 'Пульс Заботы', 'https://pulscare.ru', '+79119104012', 'Линия заботы', 'https://max.ru/u/f9LHodD0cOK9bS67jG-4VDuTSVNFBV-fV0bniFl5mVY8LWf-hhPpnmp4kV4', 'Высший стандарт патронажной помощи. Создаём пространство заботы и уважения с 2022 года.', '{"hero":{"title_lines":["Профессиональный","уход за вашими","близкими на дому"],"lead":"Проверенные сиделки, личный менеджер и контроль качества 24/7. Вернем спокойствие в вашу семью.","cta":"Начать подбор"},"safety_cards":[{"meta":"Работаем с 2022 года","lines":["Более 5000","довольных семей."]},{"meta":"100% проверка персонала","lines":["Отбор проходят","только 5% кандидатов."]},{"meta":"Личный куратор","lines":["Поддержка и","контроль 24/7."]}],"about":{"kicker":"о нас","title":"«Пульс Заботы» - это команда, которая превращает уход в понятную и надежную систему"},"services":{"kicker":"спектр поддержки","title":"Ваш выбор в пользу надёжности и опыта"}}'::jsonb, '{"pages":[{"slug":"privacy-policy","title":"Политика обработки персональных данных","lead":"Как мы собираем, используем и защищаем персональные данные пользователей сервиса.","note":"Актуально на 2026-03-28"},{"slug":"public-offer","title":"Публичная оферта","lead":"Условия предоставления услуг по подбору сиделок.","note":"Актуально на 2026-03-28"},{"slug":"service-rules","title":"Правила оказания услуг","lead":"Порядок работы сервиса, права и обязанности сторон.","note":"Актуально на 2026-03-28"}]}'::jsonb, now())
