INSERT INTO pc_seo_hub (id, path, title, lead, intro, cta_text, faq, updated_at)
VALUES (1, '/articles', '240 SEO-страниц по сложному уходу: Москва, районы Москвы, СПб и районы Санкт-Петербурга', 'Раздел построен под высоко-, средне- и низкочастотные запросы: с проживанием, круглосуточно, срочно и на дому при сложных диагнозах.', 'Сейчас в разделе: 60 базовых страниц по Москве, 30 базовых по СПб и еще 150 районных страниц с уникальными формулировками, FAQ и научными ссылками.', 'Нужен точный подбор сиделки под ваш диагноз и район? Оставьте заявку: сформируем персональный маршрут ухода и предложим релевантных кандидатов.', '[{"question":"Зачем делать отдельные страницы под районы Москвы и СПб?","answer":"Районная детализация закрывает длинные низкочастотные запросы и повышает релевантность для семей, которые ищут помощь в конкретной локации."},{"question":"Чем эти страницы отличаются от типовых SEO-текстов?","answer":"Каждая страница содержит клинический профиль, блок обучения сиделок, районный FAQ, НЧ-кластер и подтверждающие научные источники."}]'::jsonb, now())
ON CONFLICT (id) DO UPDATE SET
  path = EXCLUDED.path,
