TRUNCATE TABLE pc_seo_common_faq RESTART IDENTITY;
INSERT INTO pc_seo_common_faq (sort_order, question, answer, updated_at) VALUES (1, 'Вы работаете только по шаблону или подстраиваете уход под диагноз?', 'Всегда адаптируем алгоритм под конкретный клинический сценарий. Шаблонные чек-листы используем как базу контроля, а не как ограничение.', now());
INSERT INTO pc_seo_common_faq (sort_order, question, answer, updated_at) VALUES (2, 'Есть ли сопровождение семьи после старта ухода?', 'Да, после запуска сиделки остается куратор, который отслеживает качество и помогает корректировать формат при изменении состояния подопечного.', now());
INSERT INTO pc_seo_common_faq (sort_order, question, answer, updated_at) VALUES (3, 'Работаете ли вы с сочетанными диагнозами?', 'Да, включая сложные комбинации: деменция + маломобильность, онкология + паллиативный этап, постинсультные ограничения и другие сочетания.', now());
TRUNCATE TABLE pc_seo_pages RESTART IDENTITY;

INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-alzheimer-moskva-s-prozhivaniem', '/sidelka-alzheimer-moskva-s-prozhivaniem', 'Альцгеймер Москва', 'Сиделка с проживанием при болезни Альцгеймера в Москве', 'Сиделка с проживанием при Альцгеймер в Москве - Пульс Заботы', 'Подбор сиделки с проживанием при болезни Альцгеймера в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Профессиональный уход с проживанием при болезни Альцгеймера в Москве.',
  '[{"heading":"Как организован уход при болезни Альцгеймера","points":["Оцениваем риски: ночная спутанность, риск ухода из дома, контроль лекарств.","Формируем персональный режим дня, питания, отдыха и гигиены.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с эпизодами дезориентации в Москве","уход с проживанием при болезни Альцгеймера в Москве","сиделка с проживанием Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера москве недорого","помощь семье при ночная спутанность и риск ухода из дома москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при болезни Альцгеймера в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-alzheimer-moskva-kruglosutochno', '/sidelka-alzheimer-moskva-kruglosutochno', 'Альцгеймер Москва', 'Сиделка круглосуточно при болезни Альцгеймера в Москве', 'Сиделка круглосуточно при Альцгеймер в Москве - Пульс Заботы', 'Подбор сиделки круглосуточно при болезни Альцгеймера в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход круглосуточно при болезни Альцгеймера в Москве.',
  '[{"heading":"Как организован уход при болезни Альцгеймера","points":["Оцениваем риски: ночная спутанность, риск ухода из дома, контроль лекарств.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с эпизодами дезориентации в Москве","уход круглосуточно при болезни Альцгеймера в Москве","круглосуточная сиделка Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера москве недорого","помощь семье при ночная спутанность и риск ухода из дома москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при болезни Альцгеймера в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


