INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-parkinson-moskva-srochno', '/sidelka-parkinson-moskva-srochno', 'Паркинсон Москва', 'Сиделка срочно при болезни Паркинсона в Москве', 'Сиделка срочно при Паркинсон в Москве - Пульс Заботы', 'Подбор сиделки срочно при болезни Паркинсона в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Профессиональный уход срочно при болезни Паркинсона в Москве.',
  '[{"heading":"Как организован уход при болезни Паркинсона","points":["Оцениваем риски: риск падений, замирания, режим препаратов.","Формируем персональный режим дня, питания, отдыха и гигиены.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка срочно для подопечного с тремором и нарушением походки в Москве","уход срочно при болезни Паркинсона в Москве","срочно сиделка Москва паркинсон москва","подбор сиделки при болезни Паркинсона москве недорого","помощь семье при риск падений и замирания москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при болезни Паркинсона в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NINDS: Parkinson''s Disease","url":"https://www.ninds.nih.gov/health-information/disorders/parkinsons-disease"},{"title":"NINDS: Parkinson’s Disease - Hope Through Research","url":"https://www.ninds.nih.gov/sites/default/files/2025-05/parkinsons-disease-hope-through-research.pdf"}]'::jsonb, now()
);


