) VALUES (
  'sidelka-stroke-moskva-na-dom', '/sidelka-stroke-moskva-na-dom', 'После инсульта Москва', 'Сиделка на дому при последствиях инсульта в Москве', 'Сиделка на дому при После инсульта в Москве - Пульс Заботы', 'Подбор сиделки на дому при последствиях инсульта в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход на дому при последствиях инсульта в Москве.',
  '[{"heading":"Как организован уход при последствиях инсульта","points":["Оцениваем риски: слабость одной стороны, нарушение речи, профилактика пролежней.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка на дому для пациента в восстановительном периоде в Москве","уход на дому при последствиях инсульта в Москве","уход на дому Москва после инсульта москва","подбор сиделки при последствиях инсульта москве недорого","помощь семье при слабость одной стороны и нарушение речи москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при последствиях инсульта в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


