) VALUES (
  'sidelka-postop-moskva-na-dom', '/sidelka-postop-moskva-na-dom', 'После операции Москва', 'Сиделка на дому при восстановлении после операции в Москве', 'Сиделка на дому при После операции в Москве - Пульс Заботы', 'Подбор сиделки на дому при восстановлении после операции в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Профессиональный уход на дому при восстановлении после операции в Москве.',
  '[{"heading":"Как организован уход при восстановлении после операции","points":["Оцениваем риски: слабость, контроль режима, безопасность дома.","Формируем персональный режим дня, питания, отдыха и гигиены.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка на дому для подопечного после выписки из стационара в Москве","уход на дому при восстановлении после операции в Москве","уход на дому Москва после операции москва","подбор сиделки при восстановлении после операции москве недорого","помощь семье при слабость и контроль режима москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при восстановлении после операции в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-palliative-moskva-s-prozhivaniem', '/sidelka-palliative-moskva-s-prozhivaniem', 'Паллиативный уход Москва', 'Сиделка с проживанием при паллиативном сопровождении в Москве', 'Сиделка с проживанием при Паллиативный уход в Москве - Пульс Заботы', 'Подбор сиделки с проживанием при паллиативном сопровождении в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Профессиональный уход с проживанием при паллиативном сопровождении в Москве.',
  '[{"heading":"Как организован уход при паллиативном сопровождении","points":["Оцениваем риски: комфорт, обезболивание по назначению врача, поддержка семьи.","Формируем персональный режим дня, питания, отдыха и гигиены.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пациента с выраженной симптомной нагрузкой в Москве","уход с проживанием при паллиативном сопровождении в Москве","сиделка с проживанием Москва паллиативный уход москва","подбор сиделки при паллиативном сопровождении москве недорого","помощь семье при комфорт и обезболивание по назначению врача москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при паллиативном сопровождении в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


