) VALUES (
  'sidelka-nightcare-moskva-s-prozhivaniem', '/sidelka-nightcare-moskva-s-prozhivaniem', 'Ночной уход Москва', 'Сиделка с проживанием при сложном ночном уходе в Москве', 'Сиделка с проживанием при Ночной уход в Москве - Пульс Заботы', 'Подбор сиделки с проживанием при сложном ночном уходе в Москве: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Профессиональный уход с проживанием при сложном ночном уходе в Москве.',
  '[{"heading":"Как организован уход при сложном ночном уходе","points":["Оцениваем риски: бессонница, ночные подъемы, риск падений ночью.","Формируем персональный режим дня, питания, отдыха и гигиены.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с ночной тревожностью в Москве","уход с проживанием при сложном ночном уходе в Москве","сиделка с проживанием Москва ночной уход москва","подбор сиделки при сложном ночном уходе москве недорого","помощь семье при бессонница и ночные подъемы москве"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при сложном ночном уходе в Москве?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


