) VALUES (
  'sidelka-alzheimer-spb-kruglosutochno', '/sidelka-alzheimer-spb-kruglosutochno', 'Альцгеймер СПб', 'Сиделка круглосуточно при болезни Альцгеймера в Санкт-Петербурге', 'Сиделка круглосуточно при Альцгеймер в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при болезни Альцгеймера в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход круглосуточно при болезни Альцгеймера в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при болезни Альцгеймера","points":["Оцениваем риски: ночная спутанность, риск ухода из дома, контроль лекарств.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с эпизодами дезориентации в Санкт-Петербурге","уход круглосуточно при болезни Альцгеймера в Санкт-Петербурге","круглосуточная сиделка СПб альцгеймер спб","подбор сиделки при болезни Альцгеймера санкт-петербурге недорого","помощь семье при ночная спутанность и риск ухода из дома санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при болезни Альцгеймера в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


