  'sidelka-stroke-spb-s-prozhivaniem', '/sidelka-stroke-spb-s-prozhivaniem', 'После инсульта СПб', 'Сиделка с проживанием при последствиях инсульта в Санкт-Петербурге', 'Сиделка с проживанием при После инсульта в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при последствиях инсульта в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Профессиональный уход с проживанием при последствиях инсульта в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при последствиях инсульта","points":["Оцениваем риски: слабость одной стороны, нарушение речи, профилактика пролежней.","Формируем персональный режим дня, питания, отдыха и гигиены.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пациента в восстановительном периоде в Санкт-Петербурге","уход с проживанием при последствиях инсульта в Санкт-Петербурге","сиделка с проживанием СПб после инсульта спб","подбор сиделки при последствиях инсульта санкт-петербурге недорого","помощь семье при слабость одной стороны и нарушение речи санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при последствиях инсульта в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-stroke-spb-kruglosutochno', '/sidelka-stroke-spb-kruglosutochno', 'После инсульта СПб', 'Сиделка круглосуточно при последствиях инсульта в Санкт-Петербурге', 'Сиделка круглосуточно при После инсульта в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при последствиях инсульта в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Профессиональный уход круглосуточно при последствиях инсульта в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при последствиях инсульта","points":["Оцениваем риски: слабость одной стороны, нарушение речи, профилактика пролежней.","Формируем персональный режим дня, питания, отдыха и гигиены.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для пациента в восстановительном периоде в Санкт-Петербурге","уход круглосуточно при последствиях инсульта в Санкт-Петербурге","круглосуточная сиделка СПб после инсульта спб","подбор сиделки при последствиях инсульта санкт-петербурге недорого","помощь семье при слабость одной стороны и нарушение речи санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при последствиях инсульта в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
