) VALUES (
  'sidelka-oncology-spb-s-prozhivaniem', '/sidelka-oncology-spb-s-prozhivaniem', 'Онкология СПб', 'Сиделка с проживанием при онкологическом заболевании в Санкт-Петербурге', 'Сиделка с проживанием при Онкология в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при онкологическом заболевании в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Профессиональный уход с проживанием при онкологическом заболевании в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при онкологическом заболевании","points":["Оцениваем риски: боль и утомляемость, снижение аппетита, поддержка семьи.","Формируем персональный режим дня, питания, отдыха и гигиены.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для онкопациента с выраженной слабостью в Санкт-Петербурге","уход с проживанием при онкологическом заболевании в Санкт-Петербурге","сиделка с проживанием СПб онкология спб","подбор сиделки при онкологическом заболевании санкт-петербурге недорого","помощь семье при боль и утомляемость и снижение аппетита санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при онкологическом заболевании в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


