) VALUES (
  'sidelka-als-spb-kruglosutochno', '/sidelka-als-spb-kruglosutochno', 'БАС СПб', 'Сиделка круглосуточно при БАСе (боковом амиотрофическом склерозе) в Санкт-Петербурге', 'Сиделка круглосуточно при БАС в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при БАСе (боковом амиотрофическом склерозе) в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Профессиональный уход круглосуточно при БАСе (боковом амиотрофическом склерозе) в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при БАСе (боковом амиотрофическом склерозе)","points":["Оцениваем риски: высокая нагрузка на семью, позиционирование, длительный уход.","Формируем персональный режим дня, питания, отдыха и гигиены.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для тяжелобольного пациента с нарастающей слабостью в Санкт-Петербурге","уход круглосуточно при БАСе (боковом амиотрофическом склерозе) в Санкт-Петербурге","круглосуточная сиделка СПб бас спб","подбор сиделки при БАСе (боковом амиотрофическом склерозе) санкт-петербурге недорого","помощь семье при высокая нагрузка на семью и позиционирование санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при БАСе (боковом амиотрофическом склерозе) в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"PubMed/PMC: Caregiver burden in ALS (systematic review)","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC5784458/"},{"title":"PubMed: Coping strategies in ALS/FTD caregivers","url":"https://pubmed.ncbi.nlm.nih.gov/34937437/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-tracheostomy-spb-s-prozhivaniem', '/sidelka-tracheostomy-spb-s-prozhivaniem', 'Трахеостома СПб', 'Сиделка с проживанием при трахеостоме в Санкт-Петербурге', 'Сиделка с проживанием при Трахеостома в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при трахеостоме в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Профессиональный уход с проживанием при трахеостоме в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при трахеостоме","points":["Оцениваем риски: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Формируем персональный режим дня, питания, отдыха и гигиены.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пациента после стационара с трахеостомой в Санкт-Петербурге","уход с проживанием при трахеостоме в Санкт-Петербурге","сиделка с проживанием СПб трахеостома спб","подбор сиделки при трахеостоме санкт-петербурге недорого","помощь семье при дыхательный комфорт и гигиена санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при трахеостоме в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


