  'sidelka-tracheostomy-spb-kruglosutochno', '/sidelka-tracheostomy-spb-kruglosutochno', 'Трахеостома СПб', 'Сиделка круглосуточно при трахеостоме в Санкт-Петербурге', 'Сиделка круглосуточно при Трахеостома в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при трахеостоме в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход круглосуточно при трахеостоме в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при трахеостоме","points":["Оцениваем риски: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для пациента после стационара с трахеостомой в Санкт-Петербурге","уход круглосуточно при трахеостоме в Санкт-Петербурге","круглосуточная сиделка СПб трахеостома спб","подбор сиделки при трахеостоме санкт-петербурге недорого","помощь семье при дыхательный комфорт и гигиена санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при трахеостоме в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
