) VALUES (
  'sidelka-gastrostomy-spb-s-prozhivaniem', '/sidelka-gastrostomy-spb-s-prozhivaniem', 'Гастростома СПб', 'Сиделка с проживанием при гастростоме в Санкт-Петербурге', 'Сиделка с проживанием при Гастростома в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при гастростоме в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Профессиональный уход с проживанием при гастростоме в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при гастростоме","points":["Оцениваем риски: режим питания, уход за кожей, профилактика осложнений.","Формируем персональный режим дня, питания, отдыха и гигиены.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для лежачего пациента с ограниченной подвижностью в Санкт-Петербурге","уход с проживанием при гастростоме в Санкт-Петербурге","сиделка с проживанием СПб гастростома спб","подбор сиделки при гастростоме санкт-петербурге недорого","помощь семье при режим питания и уход за кожей санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при гастростоме в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


