) VALUES (
  'sidelka-colostomy-spb-s-prozhivaniem', '/sidelka-colostomy-spb-s-prozhivaniem', 'Колостома СПб', 'Сиделка с проживанием при колостоме в Санкт-Петербурге', 'Сиделка с проживанием при Колостома в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при колостоме в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Профессиональный уход с проживанием при колостоме в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при колостоме","points":["Оцениваем риски: деликатная гигиена, психологический комфорт, самообслуживание.","Формируем персональный режим дня, питания, отдыха и гигиены.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для подопечного после операции со стомой в Санкт-Петербурге","уход с проживанием при колостоме в Санкт-Петербурге","сиделка с проживанием СПб колостома спб","подбор сиделки при колостоме санкт-петербурге недорого","помощь семье при деликатная гигиена и психологический комфорт санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при колостоме в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-colostomy-spb-kruglosutochno', '/sidelka-colostomy-spb-kruglosutochno', 'Колостома СПб', 'Сиделка круглосуточно при колостоме в Санкт-Петербурге', 'Сиделка круглосуточно при Колостома в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при колостоме в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход круглосуточно при колостоме в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при колостоме","points":["Оцениваем риски: деликатная гигиена, психологический комфорт, самообслуживание.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для подопечного после операции со стомой в Санкт-Петербурге","уход круглосуточно при колостоме в Санкт-Петербурге","круглосуточная сиделка СПб колостома спб","подбор сиделки при колостоме санкт-петербурге недорого","помощь семье при деликатная гигиена и психологический комфорт санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при колостоме в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
