) VALUES (
  'sidelka-fracture-spb-kruglosutochno', '/sidelka-fracture-spb-kruglosutochno', 'Перелом шейки бедра СПб', 'Сиделка круглосуточно при переломе шейки бедра в Санкт-Петербурге', 'Сиделка круглосуточно при Перелом шейки бедра в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при переломе шейки бедра в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход круглосуточно при переломе шейки бедра в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при переломе шейки бедра","points":["Оцениваем риски: безопасное перемещение, пролежни, реабилитационный режим.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для маломобильного пожилого пациента в Санкт-Петербурге","уход круглосуточно при переломе шейки бедра в Санкт-Петербурге","круглосуточная сиделка СПб перелом шейки бедра спб","подбор сиделки при переломе шейки бедра санкт-петербурге недорого","помощь семье при безопасное перемещение и пролежни санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при переломе шейки бедра в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-bedridden-spb-s-prozhivaniem', '/sidelka-bedridden-spb-s-prozhivaniem', 'Лежачий больной СПб', 'Сиделка с проживанием при уходе за лежачим больным в Санкт-Петербурге', 'Сиделка с проживанием при Лежачий больной в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при уходе за лежачим больным в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Профессиональный уход с проживанием при уходе за лежачим больным в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при уходе за лежачим больным","points":["Оцениваем риски: гигиена, пролежни, повороты по графику.","Формируем персональный режим дня, питания, отдыха и гигиены.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для лежачего подопечного с постоянной потребностью в помощи в Санкт-Петербурге","уход с проживанием при уходе за лежачим больным в Санкт-Петербурге","сиделка с проживанием СПб лежачий больной спб","подбор сиделки при уходе за лежачим больным санкт-петербурге недорого","помощь семье при гигиена и пролежни санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при уходе за лежачим больным в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


