) VALUES (
  'sidelka-palliative-spb-s-prozhivaniem', '/sidelka-palliative-spb-s-prozhivaniem', 'Паллиативный уход СПб', 'Сиделка с проживанием при паллиативном сопровождении в Санкт-Петербурге', 'Сиделка с проживанием при Паллиативный уход в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при паллиативном сопровождении в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Профессиональный уход с проживанием при паллиативном сопровождении в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при паллиативном сопровождении","points":["Оцениваем риски: комфорт, обезболивание по назначению врача, поддержка семьи.","Формируем персональный режим дня, питания, отдыха и гигиены.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пациента с выраженной симптомной нагрузкой в Санкт-Петербурге","уход с проживанием при паллиативном сопровождении в Санкт-Петербурге","сиделка с проживанием СПб паллиативный уход спб","подбор сиделки при паллиативном сопровождении санкт-петербурге недорого","помощь семье при комфорт и обезболивание по назначению врача санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при паллиативном сопровождении в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-palliative-spb-kruglosutochno', '/sidelka-palliative-spb-kruglosutochno', 'Паллиативный уход СПб', 'Сиделка круглосуточно при паллиативном сопровождении в Санкт-Петербурге', 'Сиделка круглосуточно при Паллиативный уход в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при паллиативном сопровождении в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Профессиональный уход круглосуточно при паллиативном сопровождении в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при паллиативном сопровождении","points":["Оцениваем риски: комфорт, обезболивание по назначению врача, поддержка семьи.","Формируем персональный режим дня, питания, отдыха и гигиены.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для пациента с выраженной симптомной нагрузкой в Санкт-Петербурге","уход круглосуточно при паллиативном сопровождении в Санкт-Петербурге","круглосуточная сиделка СПб паллиативный уход спб","подбор сиделки при паллиативном сопровождении санкт-петербурге недорого","помощь семье при комфорт и обезболивание по назначению врача санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при паллиативном сопровождении в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-spb-s-prozhivaniem', '/sidelka-nightcare-spb-s-prozhivaniem', 'Ночной уход СПб', 'Сиделка с проживанием при сложном ночном уходе в Санкт-Петербурге', 'Сиделка с проживанием при Ночной уход в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки с проживанием при сложном ночном уходе в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Профессиональный уход с проживанием при сложном ночном уходе в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при сложном ночном уходе","points":["Оцениваем риски: бессонница, ночные подъемы, риск падений ночью.","Формируем персональный режим дня, питания, отдыха и гигиены.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с ночной тревожностью в Санкт-Петербурге","уход с проживанием при сложном ночном уходе в Санкт-Петербурге","сиделка с проживанием СПб ночной уход спб","подбор сиделки при сложном ночном уходе санкт-петербурге недорого","помощь семье при бессонница и ночные подъемы санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при сложном ночном уходе в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-spb-kruglosutochno', '/sidelka-nightcare-spb-kruglosutochno', 'Ночной уход СПб', 'Сиделка круглосуточно при сложном ночном уходе в Санкт-Петербурге', 'Сиделка круглосуточно при Ночной уход в Санкт-Петербурге - Пульс Заботы', 'Подбор сиделки круглосуточно при сложном ночном уходе в Санкт-Петербурге: обучение персонала, контроль качества, поддержка семьи 24/7.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Профессиональный уход круглосуточно при сложном ночном уходе в Санкт-Петербурге.',
  '[{"heading":"Как организован уход при сложном ночном уходе","points":["Оцениваем риски: бессонница, ночные подъемы, риск падений ночью.","Формируем персональный режим дня, питания, отдыха и гигиены.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Почему этот формат работает","points":["Снижает риск бытовых осложнений и повторных экстренных обращений.","Дает подопечному предсказуемый ритм и больше чувства безопасности.","Уменьшает эмоциональное выгорание у родственников.","Поддерживает преемственность ухода между домом и стационаром."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с ночной тревожностью в Санкт-Петербурге","уход круглосуточно при сложном ночном уходе в Санкт-Петербурге","круглосуточная сиделка СПб ночной уход спб","подбор сиделки при сложном ночном уходе санкт-петербурге недорого","помощь семье при бессонница и ночные подъемы санкт-петербурге"]'::jsonb, '[{"question":"Можно ли срочно подобрать сиделку при сложном ночном уходе в Санкт-Петербурге?","answer":"Да. В срочных кейсах запускаем подбор в день обращения и закрываем базовую безопасность до финального согласования кандидата."},{"question":"Как подтверждается квалификация сиделки?","answer":"Проверяем документы, рекомендации и практический опыт именно по профилю диагноза и формату ухода."},{"question":"Есть ли поддержка после выхода специалиста?","answer":"Да, курация продолжается после запуска ухода: мы отслеживаем обратную связь семьи и корректируем формат при необходимости."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-alzheimer-moskva-s-prozhivaniem-v-arbat', '/sidelka-alzheimer-moskva-s-prozhivaniem-v-arbat', 'Альцгеймер: Арбат', 'Сиделка с проживанием при болезни Альцгеймера в Арбат районе (Москва)', 'Сиделка с проживанием Арбат Москва - уход при Альцгеймер', 'Уход с проживанием при болезни Альцгеймера в Арбат районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Арбат районе мы выстраиваем маршрут ухода с проживанием при болезни Альцгеймера.',
  '[{"heading":"Особенности ухода в Арбат районе","points":["Учитываем логистику и доступность для семьи в Арбат районе.","Основные риски в кейсах этого профиля: ночная спутанность, риск ухода из дома, контроль лекарств.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Арбат районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с эпизодами дезориентации в Москве","сиделка с проживанием при болезни Альцгеймера в Арбат районе","сиделка с проживанием Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера арбат районе","низкочастотный запрос: уход с проживанием альцгеймер арбат"]'::jsonb, '[{"question":"Работаете ли вы в Арбат районе?","answer":"Да, мы принимаем заявки из Арбат районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Арбат районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-dementia-moskva-kruglosutochno-v-basmannyy', '/sidelka-dementia-moskva-kruglosutochno-v-basmannyy', 'Деменция: Басманный', 'Сиделка круглосуточно при деменции в Басманный районе (Москва)', 'Сиделка круглосуточно Басманный Москва - уход при Деменция', 'Уход круглосуточно при деменции в Басманный районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Басманный районе мы выстраиваем маршрут ухода круглосуточно при деменции.',
  '[{"heading":"Особенности ухода в Басманный районе","points":["Учитываем логистику и доступность для семьи в Басманный районе.","Основные риски в кейсах этого профиля: агрессия, тревожность, повторяющееся поведение.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Басманный районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с когнитивными нарушениями в Москве","сиделка круглосуточно при деменции в Басманный районе","круглосуточная сиделка Москва деменция москва","подбор сиделки при деменции басманный районе","низкочастотный запрос: уход круглосуточно деменция басманный"]'::jsonb, '[{"question":"Работаете ли вы в Басманный районе?","answer":"Да, мы принимаем заявки из Басманный районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Басманный районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-parkinson-moskva-srochno-v-zamoskvoreche', '/sidelka-parkinson-moskva-srochno-v-zamoskvoreche', 'Паркинсон: Замоскворечье', 'Сиделка срочно при болезни Паркинсона в Замоскворечье районе (Москва)', 'Сиделка срочно Замоскворечье Москва - уход при Паркинсон', 'Уход срочно при болезни Паркинсона в Замоскворечье районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Замоскворечье районе мы выстраиваем маршрут ухода срочно при болезни Паркинсона.',
  '[{"heading":"Особенности ухода в Замоскворечье районе","points":["Учитываем логистику и доступность для семьи в Замоскворечье районе.","Основные риски в кейсах этого профиля: риск падений, замирания, режим препаратов.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Замоскворечье районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для подопечного с тремором и нарушением походки в Москве","сиделка срочно при болезни Паркинсона в Замоскворечье районе","срочно сиделка Москва паркинсон москва","подбор сиделки при болезни Паркинсона замоскворечье районе","низкочастотный запрос: уход срочно паркинсон замоскворечье"]'::jsonb, '[{"question":"Работаете ли вы в Замоскворечье районе?","answer":"Да, мы принимаем заявки из Замоскворечье районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Замоскворечье районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NINDS: Parkinson''s Disease","url":"https://www.ninds.nih.gov/health-information/disorders/parkinsons-disease"},{"title":"NINDS: Parkinson’s Disease - Hope Through Research","url":"https://www.ninds.nih.gov/sites/default/files/2025-05/parkinsons-disease-hope-through-research.pdf"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
