) VALUES (
  'sidelka-stroke-moskva-na-dom-v-krasnoselskiy', '/sidelka-stroke-moskva-na-dom-v-krasnoselskiy', 'После инсульта: Красносельский', 'Сиделка на дому при последствиях инсульта в Красносельский районе (Москва)', 'Сиделка на дому Красносельский Москва - уход при После инсульта', 'Уход на дому при последствиях инсульта в Красносельский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Красносельский районе мы выстраиваем маршрут ухода на дому при последствиях инсульта.',
  '[{"heading":"Особенности ухода в Красносельский районе","points":["Учитываем логистику и доступность для семьи в Красносельский районе.","Основные риски в кейсах этого профиля: слабость одной стороны, нарушение речи, профилактика пролежней.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Красносельский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пациента в восстановительном периоде в Москве","сиделка на дому при последствиях инсульта в Красносельский районе","уход на дому Москва после инсульта москва","подбор сиделки при последствиях инсульта красносельский районе","низкочастотный запрос: уход на дому после инсульта красносельский"]'::jsonb, '[{"question":"Работаете ли вы в Красносельский районе?","answer":"Да, мы принимаем заявки из Красносельский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Красносельский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
