) VALUES (
  'sidelka-tracheostomy-moskva-srochno-v-taganskiy', '/sidelka-tracheostomy-moskva-srochno-v-taganskiy', 'Трахеостома: Таганский', 'Сиделка срочно при трахеостоме в Таганский районе (Москва)', 'Сиделка срочно Таганский Москва - уход при Трахеостома', 'Уход срочно при трахеостоме в Таганский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Таганский районе мы выстраиваем маршрут ухода срочно при трахеостоме.',
  '[{"heading":"Особенности ухода в Таганский районе","points":["Учитываем логистику и доступность для семьи в Таганский районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Таганский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пациента после стационара с трахеостомой в Москве","сиделка срочно при трахеостоме в Таганский районе","срочно сиделка Москва трахеостома москва","подбор сиделки при трахеостоме таганский районе","низкочастотный запрос: уход срочно трахеостома таганский"]'::jsonb, '[{"question":"Работаете ли вы в Таганский районе?","answer":"Да, мы принимаем заявки из Таганский районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Таганский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


