) VALUES (
  'sidelka-bedridden-moskva-na-dom-v-begovoy', '/sidelka-bedridden-moskva-na-dom-v-begovoy', 'Лежачий больной: Беговой', 'Сиделка на дому при уходе за лежачим больным в Беговой районе (Москва)', 'Сиделка на дому Беговой Москва - уход при Лежачий больной', 'Уход на дому при уходе за лежачим больным в Беговой районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Беговой районе мы выстраиваем маршрут ухода на дому при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Беговой районе","points":["Учитываем логистику и доступность для семьи в Беговой районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Беговой районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для лежачего подопечного с постоянной потребностью в помощи в Москве","сиделка на дому при уходе за лежачим больным в Беговой районе","уход на дому Москва лежачий больной москва","подбор сиделки при уходе за лежачим больным беговой районе","низкочастотный запрос: уход на дому лежачий больной беговой"]'::jsonb, '[{"question":"Работаете ли вы в Беговой районе?","answer":"Да, мы принимаем заявки из Беговой районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Беговой районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-postop-moskva-s-prozhivaniem-v-beskudnikovskiy', '/sidelka-postop-moskva-s-prozhivaniem-v-beskudnikovskiy', 'После операции: Бескудниковский', 'Сиделка с проживанием при восстановлении после операции в Бескудниковский районе (Москва)', 'Сиделка с проживанием Бескудниковский Москва - уход при После операции', 'Уход с проживанием при восстановлении после операции в Бескудниковский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Бескудниковский районе мы выстраиваем маршрут ухода с проживанием при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Бескудниковский районе","points":["Учитываем логистику и доступность для семьи в Бескудниковский районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Бескудниковский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для подопечного после выписки из стационара в Москве","сиделка с проживанием при восстановлении после операции в Бескудниковский районе","сиделка с проживанием Москва после операции москва","подбор сиделки при восстановлении после операции бескудниковский районе","низкочастотный запрос: уход с проживанием после операции бескудниковский"]'::jsonb, '[{"question":"Работаете ли вы в Бескудниковский районе?","answer":"Да, мы принимаем заявки из Бескудниковский районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Бескудниковский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-palliative-moskva-kruglosutochno-v-voykovskiy', '/sidelka-palliative-moskva-kruglosutochno-v-voykovskiy', 'Паллиативный уход: Войковский', 'Сиделка круглосуточно при паллиативном сопровождении в Войковский районе (Москва)', 'Сиделка круглосуточно Войковский Москва - уход при Паллиативный уход', 'Уход круглосуточно при паллиативном сопровождении в Войковский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Войковский районе мы выстраиваем маршрут ухода круглосуточно при паллиативном сопровождении.',
  '[{"heading":"Особенности ухода в Войковский районе","points":["Учитываем логистику и доступность для семьи в Войковский районе.","Основные риски в кейсах этого профиля: комфорт, обезболивание по назначению врача, поддержка семьи.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Войковский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пациента с выраженной симптомной нагрузкой в Москве","сиделка круглосуточно при паллиативном сопровождении в Войковский районе","круглосуточная сиделка Москва паллиативный уход москва","подбор сиделки при паллиативном сопровождении войковский районе","низкочастотный запрос: уход круглосуточно паллиативный уход войковский"]'::jsonb, '[{"question":"Работаете ли вы в Войковский районе?","answer":"Да, мы принимаем заявки из Войковский районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Войковский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-moskva-srochno-v-golovinskiy', '/sidelka-nightcare-moskva-srochno-v-golovinskiy', 'Ночной уход: Головинский', 'Сиделка срочно при сложном ночном уходе в Головинский районе (Москва)', 'Сиделка срочно Головинский Москва - уход при Ночной уход', 'Уход срочно при сложном ночном уходе в Головинский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Головинский районе мы выстраиваем маршрут ухода срочно при сложном ночном уходе.',
  '[{"heading":"Особенности ухода в Головинский районе","points":["Учитываем логистику и доступность для семьи в Головинский районе.","Основные риски в кейсах этого профиля: бессонница, ночные подъемы, риск падений ночью.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Головинский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пожилого человека с ночной тревожностью в Москве","сиделка срочно при сложном ночном уходе в Головинский районе","срочно сиделка Москва ночной уход москва","подбор сиделки при сложном ночном уходе головинский районе","низкочастотный запрос: уход срочно ночной уход головинский"]'::jsonb, '[{"question":"Работаете ли вы в Головинский районе?","answer":"Да, мы принимаем заявки из Головинский районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Головинский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


