) VALUES (
  'sidelka-bedridden-moskva-srochno-v-altufevskiy', '/sidelka-bedridden-moskva-srochno-v-altufevskiy', 'Лежачий больной: Алтуфьевский', 'Сиделка срочно при уходе за лежачим больным в Алтуфьевский районе (Москва)', 'Сиделка срочно Алтуфьевский Москва - уход при Лежачий больной', 'Уход срочно при уходе за лежачим больным в Алтуфьевский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Алтуфьевский районе мы выстраиваем маршрут ухода срочно при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Алтуфьевский районе","points":["Учитываем логистику и доступность для семьи в Алтуфьевский районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Алтуфьевский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для лежачего подопечного с постоянной потребностью в помощи в Москве","сиделка срочно при уходе за лежачим больным в Алтуфьевский районе","срочно сиделка Москва лежачий больной москва","подбор сиделки при уходе за лежачим больным алтуфьевский районе","низкочастотный запрос: уход срочно лежачий больной алтуфьевский"]'::jsonb, '[{"question":"Работаете ли вы в Алтуфьевский районе?","answer":"Да, мы принимаем заявки из Алтуфьевский районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Алтуфьевский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-postop-moskva-na-dom-v-babushkinskiy', '/sidelka-postop-moskva-na-dom-v-babushkinskiy', 'После операции: Бабушкинский', 'Сиделка на дому при восстановлении после операции в Бабушкинский районе (Москва)', 'Сиделка на дому Бабушкинский Москва - уход при После операции', 'Уход на дому при восстановлении после операции в Бабушкинский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Бабушкинский районе мы выстраиваем маршрут ухода на дому при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Бабушкинский районе","points":["Учитываем логистику и доступность для семьи в Бабушкинский районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Бабушкинский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для подопечного после выписки из стационара в Москве","сиделка на дому при восстановлении после операции в Бабушкинский районе","уход на дому Москва после операции москва","подбор сиделки при восстановлении после операции бабушкинский районе","низкочастотный запрос: уход на дому после операции бабушкинский"]'::jsonb, '[{"question":"Работаете ли вы в Бабушкинский районе?","answer":"Да, мы принимаем заявки из Бабушкинский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Бабушкинский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-palliative-moskva-s-prozhivaniem-v-bibirevo', '/sidelka-palliative-moskva-s-prozhivaniem-v-bibirevo', 'Паллиативный уход: Бибирево', 'Сиделка с проживанием при паллиативном сопровождении в Бибирево районе (Москва)', 'Сиделка с проживанием Бибирево Москва - уход при Паллиативный уход', 'Уход с проживанием при паллиативном сопровождении в Бибирево районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Бибирево районе мы выстраиваем маршрут ухода с проживанием при паллиативном сопровождении.',
  '[{"heading":"Особенности ухода в Бибирево районе","points":["Учитываем логистику и доступность для семьи в Бибирево районе.","Основные риски в кейсах этого профиля: комфорт, обезболивание по назначению врача, поддержка семьи.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Бибирево районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пациента с выраженной симптомной нагрузкой в Москве","сиделка с проживанием при паллиативном сопровождении в Бибирево районе","сиделка с проживанием Москва паллиативный уход москва","подбор сиделки при паллиативном сопровождении бибирево районе","низкочастотный запрос: уход с проживанием паллиативный уход бибирево"]'::jsonb, '[{"question":"Работаете ли вы в Бибирево районе?","answer":"Да, мы принимаем заявки из Бибирево районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Бибирево районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-moskva-kruglosutochno-v-butyrskiy', '/sidelka-nightcare-moskva-kruglosutochno-v-butyrskiy', 'Ночной уход: Бутырский', 'Сиделка круглосуточно при сложном ночном уходе в Бутырский районе (Москва)', 'Сиделка круглосуточно Бутырский Москва - уход при Ночной уход', 'Уход круглосуточно при сложном ночном уходе в Бутырский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Бутырский районе мы выстраиваем маршрут ухода круглосуточно при сложном ночном уходе.',
  '[{"heading":"Особенности ухода в Бутырский районе","points":["Учитываем логистику и доступность для семьи в Бутырский районе.","Основные риски в кейсах этого профиля: бессонница, ночные подъемы, риск падений ночью.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Бутырский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с ночной тревожностью в Москве","сиделка круглосуточно при сложном ночном уходе в Бутырский районе","круглосуточная сиделка Москва ночной уход москва","подбор сиделки при сложном ночном уходе бутырский районе","низкочастотный запрос: уход круглосуточно ночной уход бутырский"]'::jsonb, '[{"question":"Работаете ли вы в Бутырский районе?","answer":"Да, мы принимаем заявки из Бутырский районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Бутырский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
