) VALUES (
  'sidelka-alzheimer-moskva-srochno-v-lianozovo', '/sidelka-alzheimer-moskva-srochno-v-lianozovo', 'Альцгеймер: Лианозово', 'Сиделка срочно при болезни Альцгеймера в Лианозово районе (Москва)', 'Сиделка срочно Лианозово Москва - уход при Альцгеймер', 'Уход срочно при болезни Альцгеймера в Лианозово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Лианозово районе мы выстраиваем маршрут ухода срочно при болезни Альцгеймера.',
  '[{"heading":"Особенности ухода в Лианозово районе","points":["Учитываем логистику и доступность для семьи в Лианозово районе.","Основные риски в кейсах этого профиля: ночная спутанность, риск ухода из дома, контроль лекарств.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Лианозово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пожилого человека с эпизодами дезориентации в Москве","сиделка срочно при болезни Альцгеймера в Лианозово районе","срочно сиделка Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера лианозово районе","низкочастотный запрос: уход срочно альцгеймер лианозово"]'::jsonb, '[{"question":"Работаете ли вы в Лианозово районе?","answer":"Да, мы принимаем заявки из Лианозово районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Лианозово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-dementia-moskva-na-dom-v-losinoostrovskiy', '/sidelka-dementia-moskva-na-dom-v-losinoostrovskiy', 'Деменция: Лосиноостровский', 'Сиделка на дому при деменции в Лосиноостровский районе (Москва)', 'Сиделка на дому Лосиноостровский Москва - уход при Деменция', 'Уход на дому при деменции в Лосиноостровский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Лосиноостровский районе мы выстраиваем маршрут ухода на дому при деменции.',
  '[{"heading":"Особенности ухода в Лосиноостровский районе","points":["Учитываем логистику и доступность для семьи в Лосиноостровский районе.","Основные риски в кейсах этого профиля: агрессия, тревожность, повторяющееся поведение.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Лосиноостровский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пожилого человека с когнитивными нарушениями в Москве","сиделка на дому при деменции в Лосиноостровский районе","уход на дому Москва деменция москва","подбор сиделки при деменции лосиноостровский районе","низкочастотный запрос: уход на дому деменция лосиноостровский"]'::jsonb, '[{"question":"Работаете ли вы в Лосиноостровский районе?","answer":"Да, мы принимаем заявки из Лосиноостровский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Лосиноостровский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"}]'::jsonb, now()
);


