) VALUES (
  'sidelka-tracheostomy-moskva-s-prozhivaniem-v-rostokino', '/sidelka-tracheostomy-moskva-s-prozhivaniem-v-rostokino', 'Трахеостома: Ростокино', 'Сиделка с проживанием при трахеостоме в Ростокино районе (Москва)', 'Сиделка с проживанием Ростокино Москва - уход при Трахеостома', 'Уход с проживанием при трахеостоме в Ростокино районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Ростокино районе мы выстраиваем маршрут ухода с проживанием при трахеостоме.',
  '[{"heading":"Особенности ухода в Ростокино районе","points":["Учитываем логистику и доступность для семьи в Ростокино районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ростокино районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пациента после стационара с трахеостомой в Москве","сиделка с проживанием при трахеостоме в Ростокино районе","сиделка с проживанием Москва трахеостома москва","подбор сиделки при трахеостоме ростокино районе","низкочастотный запрос: уход с проживанием трахеостома ростокино"]'::jsonb, '[{"question":"Работаете ли вы в Ростокино районе?","answer":"Да, мы принимаем заявки из Ростокино районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Ростокино районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-gastrostomy-moskva-kruglosutochno-v-sviblovo', '/sidelka-gastrostomy-moskva-kruglosutochno-v-sviblovo', 'Гастростома: Свиблово', 'Сиделка круглосуточно при гастростоме в Свиблово районе (Москва)', 'Сиделка круглосуточно Свиблово Москва - уход при Гастростома', 'Уход круглосуточно при гастростоме в Свиблово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Свиблово районе мы выстраиваем маршрут ухода круглосуточно при гастростоме.',
  '[{"heading":"Особенности ухода в Свиблово районе","points":["Учитываем логистику и доступность для семьи в Свиблово районе.","Основные риски в кейсах этого профиля: режим питания, уход за кожей, профилактика осложнений.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Свиблово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для лежачего пациента с ограниченной подвижностью в Москве","сиделка круглосуточно при гастростоме в Свиблово районе","круглосуточная сиделка Москва гастростома москва","подбор сиделки при гастростоме свиблово районе","низкочастотный запрос: уход круглосуточно гастростома свиблово"]'::jsonb, '[{"question":"Работаете ли вы в Свиблово районе?","answer":"Да, мы принимаем заявки из Свиблово районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Свиблово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-colostomy-moskva-srochno-v-severnoe-medvedkovo', '/sidelka-colostomy-moskva-srochno-v-severnoe-medvedkovo', 'Колостома: Северное Медведково', 'Сиделка срочно при колостоме в Северное Медведково районе (Москва)', 'Сиделка срочно Северное Медведково Москва - уход при Колостома', 'Уход срочно при колостоме в Северное Медведково районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Северное Медведково районе мы выстраиваем маршрут ухода срочно при колостоме.',
  '[{"heading":"Особенности ухода в Северное Медведково районе","points":["Учитываем логистику и доступность для семьи в Северное Медведково районе.","Основные риски в кейсах этого профиля: деликатная гигиена, психологический комфорт, самообслуживание.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Северное Медведково районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для подопечного после операции со стомой в Москве","сиделка срочно при колостоме в Северное Медведково районе","срочно сиделка Москва колостома москва","подбор сиделки при колостоме северное медведково районе","низкочастотный запрос: уход срочно колостома северное медведково"]'::jsonb, '[{"question":"Работаете ли вы в Северное Медведково районе?","answer":"Да, мы принимаем заявки из Северное Медведково районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Северное Медведково районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


