  'sidelka-fracture-moskva-s-prozhivaniem-v-yuzhnoe-medvedkovo', '/sidelka-fracture-moskva-s-prozhivaniem-v-yuzhnoe-medvedkovo', 'Перелом шейки бедра: Южное Медведково', 'Сиделка с проживанием при переломе шейки бедра в Южное Медведково районе (Москва)', 'Сиделка с проживанием Южное Медведково Москва - уход при Перелом шейки бедра', 'Уход с проживанием при переломе шейки бедра в Южное Медведково районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Южное Медведково районе мы выстраиваем маршрут ухода с проживанием при переломе шейки бедра.',
  '[{"heading":"Особенности ухода в Южное Медведково районе","points":["Учитываем логистику и доступность для семьи в Южное Медведково районе.","Основные риски в кейсах этого профиля: безопасное перемещение, пролежни, реабилитационный режим.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Южное Медведково районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для маломобильного пожилого пациента в Москве","сиделка с проживанием при переломе шейки бедра в Южное Медведково районе","сиделка с проживанием Москва перелом шейки бедра москва","подбор сиделки при переломе шейки бедра южное медведково районе","низкочастотный запрос: уход с проживанием перелом шейки бедра южное медведково"]'::jsonb, '[{"question":"Работаете ли вы в Южное Медведково районе?","answer":"Да, мы принимаем заявки из Южное Медведково районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Южное Медведково районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-bedridden-moskva-kruglosutochno-v-yaroslavskiy', '/sidelka-bedridden-moskva-kruglosutochno-v-yaroslavskiy', 'Лежачий больной: Ярославский', 'Сиделка круглосуточно при уходе за лежачим больным в Ярославский районе (Москва)', 'Сиделка круглосуточно Ярославский Москва - уход при Лежачий больной', 'Уход круглосуточно при уходе за лежачим больным в Ярославский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Ярославский районе мы выстраиваем маршрут ухода круглосуточно при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Ярославский районе","points":["Учитываем логистику и доступность для семьи в Ярославский районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ярославский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для лежачего подопечного с постоянной потребностью в помощи в Москве","сиделка круглосуточно при уходе за лежачим больным в Ярославский районе","круглосуточная сиделка Москва лежачий больной москва","подбор сиделки при уходе за лежачим больным ярославский районе","низкочастотный запрос: уход круглосуточно лежачий больной ярославский"]'::jsonb, '[{"question":"Работаете ли вы в Ярославский районе?","answer":"Да, мы принимаем заявки из Ярославский районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Ярославский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-postop-moskva-srochno-v-bogorodskoe', '/sidelka-postop-moskva-srochno-v-bogorodskoe', 'После операции: Богородское', 'Сиделка срочно при восстановлении после операции в Богородское районе (Москва)', 'Сиделка срочно Богородское Москва - уход при После операции', 'Уход срочно при восстановлении после операции в Богородское районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Богородское районе мы выстраиваем маршрут ухода срочно при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Богородское районе","points":["Учитываем логистику и доступность для семьи в Богородское районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Богородское районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для подопечного после выписки из стационара в Москве","сиделка срочно при восстановлении после операции в Богородское районе","срочно сиделка Москва после операции москва","подбор сиделки при восстановлении после операции богородское районе","низкочастотный запрос: уход срочно после операции богородское"]'::jsonb, '[{"question":"Работаете ли вы в Богородское районе?","answer":"Да, мы принимаем заявки из Богородское районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Богородское районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


