) VALUES (
  'sidelka-palliative-moskva-na-dom-v-veshnyaki', '/sidelka-palliative-moskva-na-dom-v-veshnyaki', 'Паллиативный уход: Вешняки', 'Сиделка на дому при паллиативном сопровождении в Вешняки районе (Москва)', 'Сиделка на дому Вешняки Москва - уход при Паллиативный уход', 'Уход на дому при паллиативном сопровождении в Вешняки районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Вешняки районе мы выстраиваем маршрут ухода на дому при паллиативном сопровождении.',
  '[{"heading":"Особенности ухода в Вешняки районе","points":["Учитываем логистику и доступность для семьи в Вешняки районе.","Основные риски в кейсах этого профиля: комфорт, обезболивание по назначению врача, поддержка семьи.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Вешняки районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пациента с выраженной симптомной нагрузкой в Москве","сиделка на дому при паллиативном сопровождении в Вешняки районе","уход на дому Москва паллиативный уход москва","подбор сиделки при паллиативном сопровождении вешняки районе","низкочастотный запрос: уход на дому паллиативный уход вешняки"]'::jsonb, '[{"question":"Работаете ли вы в Вешняки районе?","answer":"Да, мы принимаем заявки из Вешняки районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Вешняки районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


