) VALUES (
  'sidelka-dementia-moskva-srochno-v-ivanovskoe', '/sidelka-dementia-moskva-srochno-v-ivanovskoe', 'Деменция: Ивановское', 'Сиделка срочно при деменции в Ивановское районе (Москва)', 'Сиделка срочно Ивановское Москва - уход при Деменция', 'Уход срочно при деменции в Ивановское районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Ивановское районе мы выстраиваем маршрут ухода срочно при деменции.',
  '[{"heading":"Особенности ухода в Ивановское районе","points":["Учитываем логистику и доступность для семьи в Ивановское районе.","Основные риски в кейсах этого профиля: агрессия, тревожность, повторяющееся поведение.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ивановское районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пожилого человека с когнитивными нарушениями в Москве","сиделка срочно при деменции в Ивановское районе","срочно сиделка Москва деменция москва","подбор сиделки при деменции ивановское районе","низкочастотный запрос: уход срочно деменция ивановское"]'::jsonb, '[{"question":"Работаете ли вы в Ивановское районе?","answer":"Да, мы принимаем заявки из Ивановское районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Ивановское районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"}]'::jsonb, now()
);


