  'sidelka-stroke-moskva-s-prozhivaniem-v-kosino-uhtomskiy', '/sidelka-stroke-moskva-s-prozhivaniem-v-kosino-uhtomskiy', 'После инсульта: Косино-Ухтомский', 'Сиделка с проживанием при последствиях инсульта в Косино-Ухтомский районе (Москва)', 'Сиделка с проживанием Косино-Ухтомский Москва - уход при После инсульта', 'Уход с проживанием при последствиях инсульта в Косино-Ухтомский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Косино-Ухтомский районе мы выстраиваем маршрут ухода с проживанием при последствиях инсульта.',
  '[{"heading":"Особенности ухода в Косино-Ухтомский районе","points":["Учитываем логистику и доступность для семьи в Косино-Ухтомский районе.","Основные риски в кейсах этого профиля: слабость одной стороны, нарушение речи, профилактика пролежней.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Косино-Ухтомский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пациента в восстановительном периоде в Москве","сиделка с проживанием при последствиях инсульта в Косино-Ухтомский районе","сиделка с проживанием Москва после инсульта москва","подбор сиделки при последствиях инсульта косино-ухтомский районе","низкочастотный запрос: уход с проживанием после инсульта косино-ухтомский"]'::jsonb, '[{"question":"Работаете ли вы в Косино-Ухтомский районе?","answer":"Да, мы принимаем заявки из Косино-Ухтомский районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Косино-Ухтомский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
