) VALUES (
  'sidelka-tracheostomy-moskva-na-dom-v-novokosino', '/sidelka-tracheostomy-moskva-na-dom-v-novokosino', 'Трахеостома: Новокосино', 'Сиделка на дому при трахеостоме в Новокосино районе (Москва)', 'Сиделка на дому Новокосино Москва - уход при Трахеостома', 'Уход на дому при трахеостоме в Новокосино районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Новокосино районе мы выстраиваем маршрут ухода на дому при трахеостоме.',
  '[{"heading":"Особенности ухода в Новокосино районе","points":["Учитываем логистику и доступность для семьи в Новокосино районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Новокосино районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пациента после стационара с трахеостомой в Москве","сиделка на дому при трахеостоме в Новокосино районе","уход на дому Москва трахеостома москва","подбор сиделки при трахеостоме новокосино районе","низкочастотный запрос: уход на дому трахеостома новокосино"]'::jsonb, '[{"question":"Работаете ли вы в Новокосино районе?","answer":"Да, мы принимаем заявки из Новокосино районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Новокосино районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-gastrostomy-moskva-s-prozhivaniem-v-perovo', '/sidelka-gastrostomy-moskva-s-prozhivaniem-v-perovo', 'Гастростома: Перово', 'Сиделка с проживанием при гастростоме в Перово районе (Москва)', 'Сиделка с проживанием Перово Москва - уход при Гастростома', 'Уход с проживанием при гастростоме в Перово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Перово районе мы выстраиваем маршрут ухода с проживанием при гастростоме.',
  '[{"heading":"Особенности ухода в Перово районе","points":["Учитываем логистику и доступность для семьи в Перово районе.","Основные риски в кейсах этого профиля: режим питания, уход за кожей, профилактика осложнений.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Перово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для лежачего пациента с ограниченной подвижностью в Москве","сиделка с проживанием при гастростоме в Перово районе","сиделка с проживанием Москва гастростома москва","подбор сиделки при гастростоме перово районе","низкочастотный запрос: уход с проживанием гастростома перово"]'::jsonb, '[{"question":"Работаете ли вы в Перово районе?","answer":"Да, мы принимаем заявки из Перово районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Перово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


