  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-bedridden-moskva-s-prozhivaniem-v-sokolniki', '/sidelka-bedridden-moskva-s-prozhivaniem-v-sokolniki', 'Лежачий больной: Сокольники', 'Сиделка с проживанием при уходе за лежачим больным в Сокольники районе (Москва)', 'Сиделка с проживанием Сокольники Москва - уход при Лежачий больной', 'Уход с проживанием при уходе за лежачим больным в Сокольники районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Сокольники районе мы выстраиваем маршрут ухода с проживанием при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Сокольники районе","points":["Учитываем логистику и доступность для семьи в Сокольники районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Сокольники районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для лежачего подопечного с постоянной потребностью в помощи в Москве","сиделка с проживанием при уходе за лежачим больным в Сокольники районе","сиделка с проживанием Москва лежачий больной москва","подбор сиделки при уходе за лежачим больным сокольники районе","низкочастотный запрос: уход с проживанием лежачий больной сокольники"]'::jsonb, '[{"question":"Работаете ли вы в Сокольники районе?","answer":"Да, мы принимаем заявки из Сокольники районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Сокольники районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-postop-moskva-kruglosutochno-v-vnukovo', '/sidelka-postop-moskva-kruglosutochno-v-vnukovo', 'После операции: Внуково', 'Сиделка круглосуточно при восстановлении после операции в Внуково районе (Москва)', 'Сиделка круглосуточно Внуково Москва - уход при После операции', 'Уход круглосуточно при восстановлении после операции в Внуково районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Внуково районе мы выстраиваем маршрут ухода круглосуточно при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Внуково районе","points":["Учитываем логистику и доступность для семьи в Внуково районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Внуково районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для подопечного после выписки из стационара в Москве","сиделка круглосуточно при восстановлении после операции в Внуково районе","круглосуточная сиделка Москва после операции москва","подбор сиделки при восстановлении после операции внуково районе","низкочастотный запрос: уход круглосуточно после операции внуково"]'::jsonb, '[{"question":"Работаете ли вы в Внуково районе?","answer":"Да, мы принимаем заявки из Внуково районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Внуково районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-palliative-moskva-srochno-v-dorogomilovo', '/sidelka-palliative-moskva-srochno-v-dorogomilovo', 'Паллиативный уход: Дорогомилово', 'Сиделка срочно при паллиативном сопровождении в Дорогомилово районе (Москва)', 'Сиделка срочно Дорогомилово Москва - уход при Паллиативный уход', 'Уход срочно при паллиативном сопровождении в Дорогомилово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Дорогомилово районе мы выстраиваем маршрут ухода срочно при паллиативном сопровождении.',
  '[{"heading":"Особенности ухода в Дорогомилово районе","points":["Учитываем логистику и доступность для семьи в Дорогомилово районе.","Основные риски в кейсах этого профиля: комфорт, обезболивание по назначению врача, поддержка семьи.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Дорогомилово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пациента с выраженной симптомной нагрузкой в Москве","сиделка срочно при паллиативном сопровождении в Дорогомилово районе","срочно сиделка Москва паллиативный уход москва","подбор сиделки при паллиативном сопровождении дорогомилово районе","низкочастотный запрос: уход срочно паллиативный уход дорогомилово"]'::jsonb, '[{"question":"Работаете ли вы в Дорогомилово районе?","answer":"Да, мы принимаем заявки из Дорогомилово районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Дорогомилово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-moskva-na-dom-v-krylatskoe', '/sidelka-nightcare-moskva-na-dom-v-krylatskoe', 'Ночной уход: Крылатское', 'Сиделка на дому при сложном ночном уходе в Крылатское районе (Москва)', 'Сиделка на дому Крылатское Москва - уход при Ночной уход', 'Уход на дому при сложном ночном уходе в Крылатское районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Крылатское районе мы выстраиваем маршрут ухода на дому при сложном ночном уходе.',
  '[{"heading":"Особенности ухода в Крылатское районе","points":["Учитываем логистику и доступность для семьи в Крылатское районе.","Основные риски в кейсах этого профиля: бессонница, ночные подъемы, риск падений ночью.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Крылатское районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пожилого человека с ночной тревожностью в Москве","сиделка на дому при сложном ночном уходе в Крылатское районе","уход на дому Москва ночной уход москва","подбор сиделки при сложном ночном уходе крылатское районе","низкочастотный запрос: уход на дому ночной уход крылатское"]'::jsonb, '[{"question":"Работаете ли вы в Крылатское районе?","answer":"Да, мы принимаем заявки из Крылатское районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Крылатское районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


