  'sidelka-alzheimer-moskva-s-prozhivaniem-v-kuntsevo', '/sidelka-alzheimer-moskva-s-prozhivaniem-v-kuntsevo', 'Альцгеймер: Кунцево', 'Сиделка с проживанием при болезни Альцгеймера в Кунцево районе (Москва)', 'Сиделка с проживанием Кунцево Москва - уход при Альцгеймер', 'Уход с проживанием при болезни Альцгеймера в Кунцево районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Кунцево районе мы выстраиваем маршрут ухода с проживанием при болезни Альцгеймера.',
  '[{"heading":"Особенности ухода в Кунцево районе","points":["Учитываем логистику и доступность для семьи в Кунцево районе.","Основные риски в кейсах этого профиля: ночная спутанность, риск ухода из дома, контроль лекарств.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Кунцево районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с эпизодами дезориентации в Москве","сиделка с проживанием при болезни Альцгеймера в Кунцево районе","сиделка с проживанием Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера кунцево районе","низкочастотный запрос: уход с проживанием альцгеймер кунцево"]'::jsonb, '[{"question":"Работаете ли вы в Кунцево районе?","answer":"Да, мы принимаем заявки из Кунцево районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Кунцево районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
