) VALUES (
  'sidelka-dementia-moskva-kruglosutochno-v-mozhayskiy', '/sidelka-dementia-moskva-kruglosutochno-v-mozhayskiy', 'Деменция: Можайский', 'Сиделка круглосуточно при деменции в Можайский районе (Москва)', 'Сиделка круглосуточно Можайский Москва - уход при Деменция', 'Уход круглосуточно при деменции в Можайский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Можайский районе мы выстраиваем маршрут ухода круглосуточно при деменции.',
  '[{"heading":"Особенности ухода в Можайский районе","points":["Учитываем логистику и доступность для семьи в Можайский районе.","Основные риски в кейсах этого профиля: агрессия, тревожность, повторяющееся поведение.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Можайский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с когнитивными нарушениями в Москве","сиделка круглосуточно при деменции в Можайский районе","круглосуточная сиделка Москва деменция москва","подбор сиделки при деменции можайский районе","низкочастотный запрос: уход круглосуточно деменция можайский"]'::jsonb, '[{"question":"Работаете ли вы в Можайский районе?","answer":"Да, мы принимаем заявки из Можайский районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Можайский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-parkinson-moskva-srochno-v-novo-peredelkino', '/sidelka-parkinson-moskva-srochno-v-novo-peredelkino', 'Паркинсон: Ново-Переделкино', 'Сиделка срочно при болезни Паркинсона в Ново-Переделкино районе (Москва)', 'Сиделка срочно Ново-Переделкино Москва - уход при Паркинсон', 'Уход срочно при болезни Паркинсона в Ново-Переделкино районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Ново-Переделкино районе мы выстраиваем маршрут ухода срочно при болезни Паркинсона.',
  '[{"heading":"Особенности ухода в Ново-Переделкино районе","points":["Учитываем логистику и доступность для семьи в Ново-Переделкино районе.","Основные риски в кейсах этого профиля: риск падений, замирания, режим препаратов.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ново-Переделкино районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для подопечного с тремором и нарушением походки в Москве","сиделка срочно при болезни Паркинсона в Ново-Переделкино районе","срочно сиделка Москва паркинсон москва","подбор сиделки при болезни Паркинсона ново-переделкино районе","низкочастотный запрос: уход срочно паркинсон ново-переделкино"]'::jsonb, '[{"question":"Работаете ли вы в Ново-Переделкино районе?","answer":"Да, мы принимаем заявки из Ново-Переделкино районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Ново-Переделкино районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NINDS: Parkinson''s Disease","url":"https://www.ninds.nih.gov/health-information/disorders/parkinsons-disease"},{"title":"NINDS: Parkinson’s Disease - Hope Through Research","url":"https://www.ninds.nih.gov/sites/default/files/2025-05/parkinsons-disease-hope-through-research.pdf"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-stroke-moskva-na-dom-v-ochakovo-matveevskoe', '/sidelka-stroke-moskva-na-dom-v-ochakovo-matveevskoe', 'После инсульта: Очаково-Матвеевское', 'Сиделка на дому при последствиях инсульта в Очаково-Матвеевское районе (Москва)', 'Сиделка на дому Очаково-Матвеевское Москва - уход при После инсульта', 'Уход на дому при последствиях инсульта в Очаково-Матвеевское районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Очаково-Матвеевское районе мы выстраиваем маршрут ухода на дому при последствиях инсульта.',
  '[{"heading":"Особенности ухода в Очаково-Матвеевское районе","points":["Учитываем логистику и доступность для семьи в Очаково-Матвеевское районе.","Основные риски в кейсах этого профиля: слабость одной стороны, нарушение речи, профилактика пролежней.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Очаково-Матвеевское районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пациента в восстановительном периоде в Москве","сиделка на дому при последствиях инсульта в Очаково-Матвеевское районе","уход на дому Москва после инсульта москва","подбор сиделки при последствиях инсульта очаково-матвеевское районе","низкочастотный запрос: уход на дому после инсульта очаково-матвеевское"]'::jsonb, '[{"question":"Работаете ли вы в Очаково-Матвеевское районе?","answer":"Да, мы принимаем заявки из Очаково-Матвеевское районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Очаково-Матвеевское районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-oncology-moskva-s-prozhivaniem-v-prospekt-vernadskogo', '/sidelka-oncology-moskva-s-prozhivaniem-v-prospekt-vernadskogo', 'Онкология: Проспект Вернадского', 'Сиделка с проживанием при онкологическом заболевании в Проспект Вернадского районе (Москва)', 'Сиделка с проживанием Проспект Вернадского Москва - уход при Онкология', 'Уход с проживанием при онкологическом заболевании в Проспект Вернадского районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Проспект Вернадского районе мы выстраиваем маршрут ухода с проживанием при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Проспект Вернадского районе","points":["Учитываем логистику и доступность для семьи в Проспект Вернадского районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Проспект Вернадского районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для онкопациента с выраженной слабостью в Москве","сиделка с проживанием при онкологическом заболевании в Проспект Вернадского районе","сиделка с проживанием Москва онкология москва","подбор сиделки при онкологическом заболевании проспект вернадского районе","низкочастотный запрос: уход с проживанием онкология проспект вернадского"]'::jsonb, '[{"question":"Работаете ли вы в Проспект Вернадского районе?","answer":"Да, мы принимаем заявки из Проспект Вернадского районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Проспект Вернадского районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


