) VALUES (
  'sidelka-colostomy-moskva-s-prozhivaniem-v-filevskiy-park', '/sidelka-colostomy-moskva-s-prozhivaniem-v-filevskiy-park', 'Колостома: Филевский Парк', 'Сиделка с проживанием при колостоме в Филевский Парк районе (Москва)', 'Сиделка с проживанием Филевский Парк Москва - уход при Колостома', 'Уход с проживанием при колостоме в Филевский Парк районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Филевский Парк районе мы выстраиваем маршрут ухода с проживанием при колостоме.',
  '[{"heading":"Особенности ухода в Филевский Парк районе","points":["Учитываем логистику и доступность для семьи в Филевский Парк районе.","Основные риски в кейсах этого профиля: деликатная гигиена, психологический комфорт, самообслуживание.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Филевский Парк районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для подопечного после операции со стомой в Москве","сиделка с проживанием при колостоме в Филевский Парк районе","сиделка с проживанием Москва колостома москва","подбор сиделки при колостоме филевский парк районе","низкочастотный запрос: уход с проживанием колостома филевский парк"]'::jsonb, '[{"question":"Работаете ли вы в Филевский Парк районе?","answer":"Да, мы принимаем заявки из Филевский Парк районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Филевский Парк районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
