) VALUES (
  'sidelka-alzheimer-moskva-na-dom-v-lomonosovskiy', '/sidelka-alzheimer-moskva-na-dom-v-lomonosovskiy', 'Альцгеймер: Ломоносовский', 'Сиделка на дому при болезни Альцгеймера в Ломоносовский районе (Москва)', 'Сиделка на дому Ломоносовский Москва - уход при Альцгеймер', 'Уход на дому при болезни Альцгеймера в Ломоносовский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Ломоносовский районе мы выстраиваем маршрут ухода на дому при болезни Альцгеймера.',
  '[{"heading":"Особенности ухода в Ломоносовский районе","points":["Учитываем логистику и доступность для семьи в Ломоносовский районе.","Основные риски в кейсах этого профиля: ночная спутанность, риск ухода из дома, контроль лекарств.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ломоносовский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пожилого человека с эпизодами дезориентации в Москве","сиделка на дому при болезни Альцгеймера в Ломоносовский районе","уход на дому Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера ломоносовский районе","низкочастотный запрос: уход на дому альцгеймер ломоносовский"]'::jsonb, '[{"question":"Работаете ли вы в Ломоносовский районе?","answer":"Да, мы принимаем заявки из Ломоносовский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Ломоносовский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-dementia-moskva-s-prozhivaniem-v-obruchevskiy', '/sidelka-dementia-moskva-s-prozhivaniem-v-obruchevskiy', 'Деменция: Обручевский', 'Сиделка с проживанием при деменции в Обручевский районе (Москва)', 'Сиделка с проживанием Обручевский Москва - уход при Деменция', 'Уход с проживанием при деменции в Обручевский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Обручевский районе мы выстраиваем маршрут ухода с проживанием при деменции.',
  '[{"heading":"Особенности ухода в Обручевский районе","points":["Учитываем логистику и доступность для семьи в Обручевский районе.","Основные риски в кейсах этого профиля: агрессия, тревожность, повторяющееся поведение.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Обручевский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с когнитивными нарушениями в Москве","сиделка с проживанием при деменции в Обручевский районе","сиделка с проживанием Москва деменция москва","подбор сиделки при деменции обручевский районе","низкочастотный запрос: уход с проживанием деменция обручевский"]'::jsonb, '[{"question":"Работаете ли вы в Обручевский районе?","answer":"Да, мы принимаем заявки из Обручевский районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Обручевский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
