) VALUES (
  'sidelka-parkinson-moskva-kruglosutochno-v-severnoe-butovo', '/sidelka-parkinson-moskva-kruglosutochno-v-severnoe-butovo', 'Паркинсон: Северное Бутово', 'Сиделка круглосуточно при болезни Паркинсона в Северное Бутово районе (Москва)', 'Сиделка круглосуточно Северное Бутово Москва - уход при Паркинсон', 'Уход круглосуточно при болезни Паркинсона в Северное Бутово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Северное Бутово районе мы выстраиваем маршрут ухода круглосуточно при болезни Паркинсона.',
  '[{"heading":"Особенности ухода в Северное Бутово районе","points":["Учитываем логистику и доступность для семьи в Северное Бутово районе.","Основные риски в кейсах этого профиля: риск падений, замирания, режим препаратов.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Северное Бутово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для подопечного с тремором и нарушением походки в Москве","сиделка круглосуточно при болезни Паркинсона в Северное Бутово районе","круглосуточная сиделка Москва паркинсон москва","подбор сиделки при болезни Паркинсона северное бутово районе","низкочастотный запрос: уход круглосуточно паркинсон северное бутово"]'::jsonb, '[{"question":"Работаете ли вы в Северное Бутово районе?","answer":"Да, мы принимаем заявки из Северное Бутово районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Северное Бутово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NINDS: Parkinson''s Disease","url":"https://www.ninds.nih.gov/health-information/disorders/parkinsons-disease"},{"title":"NINDS: Parkinson’s Disease - Hope Through Research","url":"https://www.ninds.nih.gov/sites/default/files/2025-05/parkinsons-disease-hope-through-research.pdf"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-stroke-moskva-srochno-v-teplyy-stan', '/sidelka-stroke-moskva-srochno-v-teplyy-stan', 'После инсульта: Теплый Стан', 'Сиделка срочно при последствиях инсульта в Теплый Стан районе (Москва)', 'Сиделка срочно Теплый Стан Москва - уход при После инсульта', 'Уход срочно при последствиях инсульта в Теплый Стан районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Теплый Стан районе мы выстраиваем маршрут ухода срочно при последствиях инсульта.',
  '[{"heading":"Особенности ухода в Теплый Стан районе","points":["Учитываем логистику и доступность для семьи в Теплый Стан районе.","Основные риски в кейсах этого профиля: слабость одной стороны, нарушение речи, профилактика пролежней.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Теплый Стан районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пациента в восстановительном периоде в Москве","сиделка срочно при последствиях инсульта в Теплый Стан районе","срочно сиделка Москва после инсульта москва","подбор сиделки при последствиях инсульта теплый стан районе","низкочастотный запрос: уход срочно после инсульта теплый стан"]'::jsonb, '[{"question":"Работаете ли вы в Теплый Стан районе?","answer":"Да, мы принимаем заявки из Теплый Стан районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Теплый Стан районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


