) VALUES (
  'sidelka-oncology-moskva-na-dom-v-cheremushki', '/sidelka-oncology-moskva-na-dom-v-cheremushki', 'Онкология: Черемушки', 'Сиделка на дому при онкологическом заболевании в Черемушки районе (Москва)', 'Сиделка на дому Черемушки Москва - уход при Онкология', 'Уход на дому при онкологическом заболевании в Черемушки районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Черемушки районе мы выстраиваем маршрут ухода на дому при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Черемушки районе","points":["Учитываем логистику и доступность для семьи в Черемушки районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Черемушки районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для онкопациента с выраженной слабостью в Москве","сиделка на дому при онкологическом заболевании в Черемушки районе","уход на дому Москва онкология москва","подбор сиделки при онкологическом заболевании черемушки районе","низкочастотный запрос: уход на дому онкология черемушки"]'::jsonb, '[{"question":"Работаете ли вы в Черемушки районе?","answer":"Да, мы принимаем заявки из Черемушки районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Черемушки районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


