) VALUES (
  'sidelka-tracheostomy-moskva-kruglosutochno-v-yasenevo', '/sidelka-tracheostomy-moskva-kruglosutochno-v-yasenevo', 'Трахеостома: Ясенево', 'Сиделка круглосуточно при трахеостоме в Ясенево районе (Москва)', 'Сиделка круглосуточно Ясенево Москва - уход при Трахеостома', 'Уход круглосуточно при трахеостоме в Ясенево районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Ясенево районе мы выстраиваем маршрут ухода круглосуточно при трахеостоме.',
  '[{"heading":"Особенности ухода в Ясенево районе","points":["Учитываем логистику и доступность для семьи в Ясенево районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ясенево районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пациента после стационара с трахеостомой в Москве","сиделка круглосуточно при трахеостоме в Ясенево районе","круглосуточная сиделка Москва трахеостома москва","подбор сиделки при трахеостоме ясенево районе","низкочастотный запрос: уход круглосуточно трахеостома ясенево"]'::jsonb, '[{"question":"Работаете ли вы в Ясенево районе?","answer":"Да, мы принимаем заявки из Ясенево районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Ясенево районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-gastrostomy-moskva-srochno-v-biryulevo-vostochnoe', '/sidelka-gastrostomy-moskva-srochno-v-biryulevo-vostochnoe', 'Гастростома: Бирюлево Восточное', 'Сиделка срочно при гастростоме в Бирюлево Восточное районе (Москва)', 'Сиделка срочно Бирюлево Восточное Москва - уход при Гастростома', 'Уход срочно при гастростоме в Бирюлево Восточное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Бирюлево Восточное районе мы выстраиваем маршрут ухода срочно при гастростоме.',
  '[{"heading":"Особенности ухода в Бирюлево Восточное районе","points":["Учитываем логистику и доступность для семьи в Бирюлево Восточное районе.","Основные риски в кейсах этого профиля: режим питания, уход за кожей, профилактика осложнений.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Бирюлево Восточное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для лежачего пациента с ограниченной подвижностью в Москве","сиделка срочно при гастростоме в Бирюлево Восточное районе","срочно сиделка Москва гастростома москва","подбор сиделки при гастростоме бирюлево восточное районе","низкочастотный запрос: уход срочно гастростома бирюлево восточное"]'::jsonb, '[{"question":"Работаете ли вы в Бирюлево Восточное районе?","answer":"Да, мы принимаем заявки из Бирюлево Восточное районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Бирюлево Восточное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
