) VALUES (
  'sidelka-colostomy-moskva-na-dom-v-biryulevo-zapadnoe', '/sidelka-colostomy-moskva-na-dom-v-biryulevo-zapadnoe', 'Колостома: Бирюлево Западное', 'Сиделка на дому при колостоме в Бирюлево Западное районе (Москва)', 'Сиделка на дому Бирюлево Западное Москва - уход при Колостома', 'Уход на дому при колостоме в Бирюлево Западное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Бирюлево Западное районе мы выстраиваем маршрут ухода на дому при колостоме.',
  '[{"heading":"Особенности ухода в Бирюлево Западное районе","points":["Учитываем логистику и доступность для семьи в Бирюлево Западное районе.","Основные риски в кейсах этого профиля: деликатная гигиена, психологический комфорт, самообслуживание.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Бирюлево Западное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для подопечного после операции со стомой в Москве","сиделка на дому при колостоме в Бирюлево Западное районе","уход на дому Москва колостома москва","подбор сиделки при колостоме бирюлево западное районе","низкочастотный запрос: уход на дому колостома бирюлево западное"]'::jsonb, '[{"question":"Работаете ли вы в Бирюлево Западное районе?","answer":"Да, мы принимаем заявки из Бирюлево Западное районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Бирюлево Западное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


