INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-bedridden-moskva-srochno-v-donskoy', '/sidelka-bedridden-moskva-srochno-v-donskoy', 'Лежачий больной: Донской', 'Сиделка срочно при уходе за лежачим больным в Донской районе (Москва)', 'Сиделка срочно Донской Москва - уход при Лежачий больной', 'Уход срочно при уходе за лежачим больным в Донской районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Донской районе мы выстраиваем маршрут ухода срочно при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Донской районе","points":["Учитываем логистику и доступность для семьи в Донской районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Донской районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для лежачего подопечного с постоянной потребностью в помощи в Москве","сиделка срочно при уходе за лежачим больным в Донской районе","срочно сиделка Москва лежачий больной москва","подбор сиделки при уходе за лежачим больным донской районе","низкочастотный запрос: уход срочно лежачий больной донской"]'::jsonb, '[{"question":"Работаете ли вы в Донской районе?","answer":"Да, мы принимаем заявки из Донской районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Донской районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-postop-moskva-na-dom-v-zyablikovo', '/sidelka-postop-moskva-na-dom-v-zyablikovo', 'После операции: Зябликово', 'Сиделка на дому при восстановлении после операции в Зябликово районе (Москва)', 'Сиделка на дому Зябликово Москва - уход при После операции', 'Уход на дому при восстановлении после операции в Зябликово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Зябликово районе мы выстраиваем маршрут ухода на дому при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Зябликово районе","points":["Учитываем логистику и доступность для семьи в Зябликово районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Зябликово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для подопечного после выписки из стационара в Москве","сиделка на дому при восстановлении после операции в Зябликово районе","уход на дому Москва после операции москва","подбор сиделки при восстановлении после операции зябликово районе","низкочастотный запрос: уход на дому после операции зябликово"]'::jsonb, '[{"question":"Работаете ли вы в Зябликово районе?","answer":"Да, мы принимаем заявки из Зябликово районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Зябликово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-palliative-moskva-s-prozhivaniem-v-moskvoreche-saburovo', '/sidelka-palliative-moskva-s-prozhivaniem-v-moskvoreche-saburovo', 'Паллиативный уход: Москворечье-Сабурово', 'Сиделка с проживанием при паллиативном сопровождении в Москворечье-Сабурово районе (Москва)', 'Сиделка с проживанием Москворечье-Сабурово Москва - уход при Паллиативный уход', 'Уход с проживанием при паллиативном сопровождении в Москворечье-Сабурово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Москворечье-Сабурово районе мы выстраиваем маршрут ухода с проживанием при паллиативном сопровождении.',
  '[{"heading":"Особенности ухода в Москворечье-Сабурово районе","points":["Учитываем логистику и доступность для семьи в Москворечье-Сабурово районе.","Основные риски в кейсах этого профиля: комфорт, обезболивание по назначению врача, поддержка семьи.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Москворечье-Сабурово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пациента с выраженной симптомной нагрузкой в Москве","сиделка с проживанием при паллиативном сопровождении в Москворечье-Сабурово районе","сиделка с проживанием Москва паллиативный уход москва","подбор сиделки при паллиативном сопровождении москворечье-сабурово районе","низкочастотный запрос: уход с проживанием паллиативный уход москворечье-сабурово"]'::jsonb, '[{"question":"Работаете ли вы в Москворечье-Сабурово районе?","answer":"Да, мы принимаем заявки из Москворечье-Сабурово районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Москворечье-Сабурово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-moskva-kruglosutochno-v-nagatino-sadovniki', '/sidelka-nightcare-moskva-kruglosutochno-v-nagatino-sadovniki', 'Ночной уход: Нагатино-Садовники', 'Сиделка круглосуточно при сложном ночном уходе в Нагатино-Садовники районе (Москва)', 'Сиделка круглосуточно Нагатино-Садовники Москва - уход при Ночной уход', 'Уход круглосуточно при сложном ночном уходе в Нагатино-Садовники районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Нагатино-Садовники районе мы выстраиваем маршрут ухода круглосуточно при сложном ночном уходе.',
  '[{"heading":"Особенности ухода в Нагатино-Садовники районе","points":["Учитываем логистику и доступность для семьи в Нагатино-Садовники районе.","Основные риски в кейсах этого профиля: бессонница, ночные подъемы, риск падений ночью.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Нагатино-Садовники районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с ночной тревожностью в Москве","сиделка круглосуточно при сложном ночном уходе в Нагатино-Садовники районе","круглосуточная сиделка Москва ночной уход москва","подбор сиделки при сложном ночном уходе нагатино-садовники районе","низкочастотный запрос: уход круглосуточно ночной уход нагатино-садовники"]'::jsonb, '[{"question":"Работаете ли вы в Нагатино-Садовники районе?","answer":"Да, мы принимаем заявки из Нагатино-Садовники районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Нагатино-Садовники районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-alzheimer-moskva-srochno-v-nagatinskiy-zaton', '/sidelka-alzheimer-moskva-srochno-v-nagatinskiy-zaton', 'Альцгеймер: Нагатинский Затон', 'Сиделка срочно при болезни Альцгеймера в Нагатинский Затон районе (Москва)', 'Сиделка срочно Нагатинский Затон Москва - уход при Альцгеймер', 'Уход срочно при болезни Альцгеймера в Нагатинский Затон районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Нагатинский Затон районе мы выстраиваем маршрут ухода срочно при болезни Альцгеймера.',
  '[{"heading":"Особенности ухода в Нагатинский Затон районе","points":["Учитываем логистику и доступность для семьи в Нагатинский Затон районе.","Основные риски в кейсах этого профиля: ночная спутанность, риск ухода из дома, контроль лекарств.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Нагатинский Затон районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для пожилого человека с эпизодами дезориентации в Москве","сиделка срочно при болезни Альцгеймера в Нагатинский Затон районе","срочно сиделка Москва альцгеймер москва","подбор сиделки при болезни Альцгеймера нагатинский затон районе","низкочастотный запрос: уход срочно альцгеймер нагатинский затон"]'::jsonb, '[{"question":"Работаете ли вы в Нагатинский Затон районе?","answer":"Да, мы принимаем заявки из Нагатинский Затон районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Нагатинский Затон районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-dementia-moskva-na-dom-v-nagornyy', '/sidelka-dementia-moskva-na-dom-v-nagornyy', 'Деменция: Нагорный', 'Сиделка на дому при деменции в Нагорный районе (Москва)', 'Сиделка на дому Нагорный Москва - уход при Деменция', 'Уход на дому при деменции в Нагорный районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Нагорный районе мы выстраиваем маршрут ухода на дому при деменции.',
  '[{"heading":"Особенности ухода в Нагорный районе","points":["Учитываем логистику и доступность для семьи в Нагорный районе.","Основные риски в кейсах этого профиля: агрессия, тревожность, повторяющееся поведение.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Нагорный районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пожилого человека с когнитивными нарушениями в Москве","сиделка на дому при деменции в Нагорный районе","уход на дому Москва деменция москва","подбор сиделки при деменции нагорный районе","низкочастотный запрос: уход на дому деменция нагорный"]'::jsonb, '[{"question":"Работаете ли вы в Нагорный районе?","answer":"Да, мы принимаем заявки из Нагорный районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Нагорный районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-parkinson-moskva-s-prozhivaniem-v-orehovo-borisovo-severnoe', '/sidelka-parkinson-moskva-s-prozhivaniem-v-orehovo-borisovo-severnoe', 'Паркинсон: Орехово-Борисово Северное', 'Сиделка с проживанием при болезни Паркинсона в Орехово-Борисово Северное районе (Москва)', 'Сиделка с проживанием Орехово-Борисово Северное Москва - уход при Паркинсон', 'Уход с проживанием при болезни Паркинсона в Орехово-Борисово Северное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Орехово-Борисово Северное районе мы выстраиваем маршрут ухода с проживанием при болезни Паркинсона.',
  '[{"heading":"Особенности ухода в Орехово-Борисово Северное районе","points":["Учитываем логистику и доступность для семьи в Орехово-Борисово Северное районе.","Основные риски в кейсах этого профиля: риск падений, замирания, режим препаратов.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Орехово-Борисово Северное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для подопечного с тремором и нарушением походки в Москве","сиделка с проживанием при болезни Паркинсона в Орехово-Борисово Северное районе","сиделка с проживанием Москва паркинсон москва","подбор сиделки при болезни Паркинсона орехово-борисово северное районе","низкочастотный запрос: уход с проживанием паркинсон орехово-борисово северное"]'::jsonb, '[{"question":"Работаете ли вы в Орехово-Борисово Северное районе?","answer":"Да, мы принимаем заявки из Орехово-Борисово Северное районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Орехово-Борисово Северное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NINDS: Parkinson''s Disease","url":"https://www.ninds.nih.gov/health-information/disorders/parkinsons-disease"},{"title":"NINDS: Parkinson’s Disease - Hope Through Research","url":"https://www.ninds.nih.gov/sites/default/files/2025-05/parkinsons-disease-hope-through-research.pdf"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-stroke-moskva-kruglosutochno-v-orehovo-borisovo-yuzhnoe', '/sidelka-stroke-moskva-kruglosutochno-v-orehovo-borisovo-yuzhnoe', 'После инсульта: Орехово-Борисово Южное', 'Сиделка круглосуточно при последствиях инсульта в Орехово-Борисово Южное районе (Москва)', 'Сиделка круглосуточно Орехово-Борисово Южное Москва - уход при После инсульта', 'Уход круглосуточно при последствиях инсульта в Орехово-Борисово Южное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Орехово-Борисово Южное районе мы выстраиваем маршрут ухода круглосуточно при последствиях инсульта.',
  '[{"heading":"Особенности ухода в Орехово-Борисово Южное районе","points":["Учитываем логистику и доступность для семьи в Орехово-Борисово Южное районе.","Основные риски в кейсах этого профиля: слабость одной стороны, нарушение речи, профилактика пролежней.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Орехово-Борисово Южное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пациента в восстановительном периоде в Москве","сиделка круглосуточно при последствиях инсульта в Орехово-Борисово Южное районе","круглосуточная сиделка Москва после инсульта москва","подбор сиделки при последствиях инсульта орехово-борисово южное районе","низкочастотный запрос: уход круглосуточно после инсульта орехово-борисово южное"]'::jsonb, '[{"question":"Работаете ли вы в Орехово-Борисово Южное районе?","answer":"Да, мы принимаем заявки из Орехово-Борисово Южное районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Орехово-Борисово Южное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-oncology-moskva-srochno-v-tsaritsyno', '/sidelka-oncology-moskva-srochno-v-tsaritsyno', 'Онкология: Царицыно', 'Сиделка срочно при онкологическом заболевании в Царицыно районе (Москва)', 'Сиделка срочно Царицыно Москва - уход при Онкология', 'Уход срочно при онкологическом заболевании в Царицыно районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Царицыно районе мы выстраиваем маршрут ухода срочно при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Царицыно районе","points":["Учитываем логистику и доступность для семьи в Царицыно районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Царицыно районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для онкопациента с выраженной слабостью в Москве","сиделка срочно при онкологическом заболевании в Царицыно районе","срочно сиделка Москва онкология москва","подбор сиделки при онкологическом заболевании царицыно районе","низкочастотный запрос: уход срочно онкология царицыно"]'::jsonb, '[{"question":"Работаете ли вы в Царицыно районе?","answer":"Да, мы принимаем заявки из Царицыно районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Царицыно районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


