  'sidelka-als-moskva-na-dom-v-chertanovo-severnoe', '/sidelka-als-moskva-na-dom-v-chertanovo-severnoe', 'БАС: Чертаново Северное', 'Сиделка на дому при БАСе (боковом амиотрофическом склерозе) в Чертаново Северное районе (Москва)', 'Сиделка на дому Чертаново Северное Москва - уход при БАС', 'Уход на дому при БАСе (боковом амиотрофическом склерозе) в Чертаново Северное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Чертаново Северное районе мы выстраиваем маршрут ухода на дому при БАСе (боковом амиотрофическом склерозе).',
  '[{"heading":"Особенности ухода в Чертаново Северное районе","points":["Учитываем логистику и доступность для семьи в Чертаново Северное районе.","Основные риски в кейсах этого профиля: высокая нагрузка на семью, позиционирование, длительный уход.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Чертаново Северное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для тяжелобольного пациента с нарастающей слабостью в Москве","сиделка на дому при БАСе (боковом амиотрофическом склерозе) в Чертаново Северное районе","уход на дому Москва бас москва","подбор сиделки при БАСе (боковом амиотрофическом склерозе) чертаново северное районе","низкочастотный запрос: уход на дому бас чертаново северное"]'::jsonb, '[{"question":"Работаете ли вы в Чертаново Северное районе?","answer":"Да, мы принимаем заявки из Чертаново Северное районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Чертаново Северное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed/PMC: Caregiver burden in ALS (systematic review)","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC5784458/"},{"title":"PubMed: Coping strategies in ALS/FTD caregivers","url":"https://pubmed.ncbi.nlm.nih.gov/34937437/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
