) VALUES (
  'sidelka-tracheostomy-moskva-s-prozhivaniem-v-chertanovo-tsentralnoe', '/sidelka-tracheostomy-moskva-s-prozhivaniem-v-chertanovo-tsentralnoe', 'Трахеостома: Чертаново Центральное', 'Сиделка с проживанием при трахеостоме в Чертаново Центральное районе (Москва)', 'Сиделка с проживанием Чертаново Центральное Москва - уход при Трахеостома', 'Уход с проживанием при трахеостоме в Чертаново Центральное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Чертаново Центральное районе мы выстраиваем маршрут ухода с проживанием при трахеостоме.',
  '[{"heading":"Особенности ухода в Чертаново Центральное районе","points":["Учитываем логистику и доступность для семьи в Чертаново Центральное районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Чертаново Центральное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пациента после стационара с трахеостомой в Москве","сиделка с проживанием при трахеостоме в Чертаново Центральное районе","сиделка с проживанием Москва трахеостома москва","подбор сиделки при трахеостоме чертаново центральное районе","низкочастотный запрос: уход с проживанием трахеостома чертаново центральное"]'::jsonb, '[{"question":"Работаете ли вы в Чертаново Центральное районе?","answer":"Да, мы принимаем заявки из Чертаново Центральное районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Чертаново Центральное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-gastrostomy-moskva-kruglosutochno-v-chertanovo-yuzhnoe', '/sidelka-gastrostomy-moskva-kruglosutochno-v-chertanovo-yuzhnoe', 'Гастростома: Чертаново Южное', 'Сиделка круглосуточно при гастростоме в Чертаново Южное районе (Москва)', 'Сиделка круглосуточно Чертаново Южное Москва - уход при Гастростома', 'Уход круглосуточно при гастростоме в Чертаново Южное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Чертаново Южное районе мы выстраиваем маршрут ухода круглосуточно при гастростоме.',
  '[{"heading":"Особенности ухода в Чертаново Южное районе","points":["Учитываем логистику и доступность для семьи в Чертаново Южное районе.","Основные риски в кейсах этого профиля: режим питания, уход за кожей, профилактика осложнений.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Чертаново Южное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для лежачего пациента с ограниченной подвижностью в Москве","сиделка круглосуточно при гастростоме в Чертаново Южное районе","круглосуточная сиделка Москва гастростома москва","подбор сиделки при гастростоме чертаново южное районе","низкочастотный запрос: уход круглосуточно гастростома чертаново южное"]'::jsonb, '[{"question":"Работаете ли вы в Чертаново Южное районе?","answer":"Да, мы принимаем заявки из Чертаново Южное районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Чертаново Южное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-colostomy-moskva-srochno-v-nekrasovka', '/sidelka-colostomy-moskva-srochno-v-nekrasovka', 'Колостома: Некрасовка', 'Сиделка срочно при колостоме в Некрасовка районе (Москва)', 'Сиделка срочно Некрасовка Москва - уход при Колостома', 'Уход срочно при колостоме в Некрасовка районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Некрасовка районе мы выстраиваем маршрут ухода срочно при колостоме.',
  '[{"heading":"Особенности ухода в Некрасовка районе","points":["Учитываем логистику и доступность для семьи в Некрасовка районе.","Основные риски в кейсах этого профиля: деликатная гигиена, психологический комфорт, самообслуживание.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Некрасовка районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для подопечного после операции со стомой в Москве","сиделка срочно при колостоме в Некрасовка районе","срочно сиделка Москва колостома москва","подбор сиделки при колостоме некрасовка районе","низкочастотный запрос: уход срочно колостома некрасовка"]'::jsonb, '[{"question":"Работаете ли вы в Некрасовка районе?","answer":"Да, мы принимаем заявки из Некрасовка районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Некрасовка районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


