) VALUES (
  'sidelka-oncology-spb-kruglosutochno-v-vasileostrovskiy', '/sidelka-oncology-spb-kruglosutochno-v-vasileostrovskiy', 'Онкология: Василеостровский', 'Сиделка круглосуточно при онкологическом заболевании в Василеостровский районе (СПб)', 'Сиделка круглосуточно Василеостровский СПб - уход при Онкология', 'Уход круглосуточно при онкологическом заболевании в Василеостровский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Василеостровский районе мы выстраиваем маршрут ухода круглосуточно при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Василеостровский районе","points":["Учитываем логистику и доступность для семьи в Василеостровский районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Василеостровский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для онкопациента с выраженной слабостью в Санкт-Петербурге","сиделка круглосуточно при онкологическом заболевании в Василеостровский районе","круглосуточная сиделка СПб онкология спб","подбор сиделки при онкологическом заболевании василеостровский районе","низкочастотный запрос: уход круглосуточно онкология василеостровский"]'::jsonb, '[{"question":"Работаете ли вы в Василеостровский районе?","answer":"Да, мы принимаем заявки из Василеостровский районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Василеостровский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-als-spb-na-dom-v-vyborgskiy', '/sidelka-als-spb-na-dom-v-vyborgskiy', 'БАС: Выборгский', 'Сиделка на дому при БАСе (боковом амиотрофическом склерозе) в Выборгский районе (СПб)', 'Сиделка на дому Выборгский СПб - уход при БАС', 'Уход на дому при БАСе (боковом амиотрофическом склерозе) в Выборгский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Выборгский районе мы выстраиваем маршрут ухода на дому при БАСе (боковом амиотрофическом склерозе).',
  '[{"heading":"Особенности ухода в Выборгский районе","points":["Учитываем логистику и доступность для семьи в Выборгский районе.","Основные риски в кейсах этого профиля: высокая нагрузка на семью, позиционирование, длительный уход.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Выборгский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для тяжелобольного пациента с нарастающей слабостью в Санкт-Петербурге","сиделка на дому при БАСе (боковом амиотрофическом склерозе) в Выборгский районе","уход на дому СПб бас спб","подбор сиделки при БАСе (боковом амиотрофическом склерозе) выборгский районе","низкочастотный запрос: уход на дому бас выборгский"]'::jsonb, '[{"question":"Работаете ли вы в Выборгский районе?","answer":"Да, мы принимаем заявки из Выборгский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Выборгский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed/PMC: Caregiver burden in ALS (systematic review)","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC5784458/"},{"title":"PubMed: Coping strategies in ALS/FTD caregivers","url":"https://pubmed.ncbi.nlm.nih.gov/34937437/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
