) VALUES (
  'sidelka-diabetes-spb-na-dom-v-krasnogvardeyskiy', '/sidelka-diabetes-spb-na-dom-v-krasnogvardeyskiy', 'Диабет: Красногвардейский', 'Сиделка на дому при сахарном диабете у пожилых в Красногвардейский районе (СПб)', 'Сиделка на дому Красногвардейский СПб - уход при Диабет', 'Уход на дому при сахарном диабете у пожилых в Красногвардейский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Красногвардейский районе мы выстраиваем маршрут ухода на дому при сахарном диабете у пожилых.',
  '[{"heading":"Особенности ухода в Красногвардейский районе","points":["Учитываем логистику и доступность для семьи в Красногвардейский районе.","Основные риски в кейсах этого профиля: режим питания, контроль самочувствия, профилактика падений.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Красногвардейский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пожилого человека с сопутствующими рисками в Санкт-Петербурге","сиделка на дому при сахарном диабете у пожилых в Красногвардейский районе","уход на дому СПб диабет спб","подбор сиделки при сахарном диабете у пожилых красногвардейский районе","низкочастотный запрос: уход на дому диабет красногвардейский"]'::jsonb, '[{"question":"Работаете ли вы в Красногвардейский районе?","answer":"Да, мы принимаем заявки из Красногвардейский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Красногвардейский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Diabetes fact sheet","url":"https://www.who.int/news-room/fact-sheets/detail/diabetes"},{"title":"CDC: Helping friends and family with diabetes","url":"https://www.cdc.gov/diabetes/caring/index.html"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-fracture-spb-srochno-v-krasnoselskiy', '/sidelka-fracture-spb-srochno-v-krasnoselskiy', 'Перелом шейки бедра: Красносельский', 'Сиделка срочно при переломе шейки бедра в Красносельский районе (СПб)', 'Сиделка срочно Красносельский СПб - уход при Перелом шейки бедра', 'Уход срочно при переломе шейки бедра в Красносельский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Красносельский районе мы выстраиваем маршрут ухода срочно при переломе шейки бедра.',
  '[{"heading":"Особенности ухода в Красносельский районе","points":["Учитываем логистику и доступность для семьи в Красносельский районе.","Основные риски в кейсах этого профиля: безопасное перемещение, пролежни, реабилитационный режим.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Красносельский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для маломобильного пожилого пациента в Санкт-Петербурге","сиделка срочно при переломе шейки бедра в Красносельский районе","срочно сиделка СПб перелом шейки бедра спб","подбор сиделки при переломе шейки бедра красносельский районе","низкочастотный запрос: уход срочно перелом шейки бедра красносельский"]'::jsonb, '[{"question":"Работаете ли вы в Красносельский районе?","answer":"Да, мы принимаем заявки из Красносельский районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Красносельский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещ