);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-bedridden-spb-s-prozhivaniem-v-kronshtadtskiy', '/sidelka-bedridden-spb-s-prozhivaniem-v-kronshtadtskiy', 'Лежачий больной: Кронштадтский', 'Сиделка с проживанием при уходе за лежачим больным в Кронштадтский районе (СПб)', 'Сиделка с проживанием Кронштадтский СПб - уход при Лежачий больной', 'Уход с проживанием при уходе за лежачим больным в Кронштадтский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Кронштадтский районе мы выстраиваем маршрут ухода с проживанием при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Кронштадтский районе","points":["Учитываем логистику и доступность для семьи в Кронштадтский районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Кронштадтский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для лежачего подопечного с постоянной потребностью в помощи в Санкт-Петербурге","сиделка с проживанием при уходе за лежачим больным в Кронштадтский районе","сиделка с проживанием СПб лежачий больной спб","подбор сиделки при уходе за лежачим больным кронштадтский районе","низкочастотный запрос: уход с проживанием лежачий больной кронштадтский"]'::jsonb, '[{"question":"Работаете ли вы в Кронштадтский районе?","answer":"Да, мы принимаем заявки из Кронштадтский районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Кронштадтский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


