) VALUES (
  'sidelka-postop-spb-kruglosutochno-v-kurortnyy', '/sidelka-postop-spb-kruglosutochno-v-kurortnyy', 'После операции: Курортный', 'Сиделка круглосуточно при восстановлении после операции в Курортный районе (СПб)', 'Сиделка круглосуточно Курортный СПб - уход при После операции', 'Уход круглосуточно при восстановлении после операции в Курортный районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Курортный районе мы выстраиваем маршрут ухода круглосуточно при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Курортный районе","points":["Учитываем логистику и доступность для семьи в Курортный районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Курортный районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для подопечного после выписки из стационара в Санкт-Петербурге","сиделка круглосуточно при восстановлении после операции в Курортный районе","круглосуточная сиделка СПб после операции спб","подбор сиделки при восстановлении после операции курортный районе","низкочастотный запрос: уход круглосуточно после операции курортный"]'::jsonb, '[{"question":"Работаете ли вы в Курортный районе?","answer":"Да, мы принимаем заявки из Курортный районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Курортный районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


