) VALUES (
  'sidelka-parkinson-spb-na-dom-v-primorskiy', '/sidelka-parkinson-spb-na-dom-v-primorskiy', 'Паркинсон: Приморский', 'Сиделка на дому при болезни Паркинсона в Приморский районе (СПб)', 'Сиделка на дому Приморский СПб - уход при Паркинсон', 'Уход на дому при болезни Паркинсона в Приморский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Приморский районе мы выстраиваем маршрут ухода на дому при болезни Паркинсона.',
  '[{"heading":"Особенности ухода в Приморский районе","points":["Учитываем логистику и доступность для семьи в Приморский районе.","Основные риски в кейсах этого профиля: риск падений, замирания, режим препаратов.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Приморский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для подопечного с тремором и нарушением походки в Санкт-Петербурге","сиделка на дому при болезни Паркинсона в Приморский районе","уход на дому СПб паркинсон спб","подбор сиделки при болезни Паркинсона приморский районе","низкочастотный запрос: уход на дому паркинсон приморский"]'::jsonb, '[{"question":"Работаете ли вы в Приморский районе?","answer":"Да, мы принимаем заявки из Приморский районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Приморский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NINDS: Parkinson''s Disease","url":"https://www.ninds.nih.gov/health-information/disorders/parkinsons-disease"},{"title":"NINDS: Parkinson’s Disease - Hope Through Research","url":"https://www.ninds.nih.gov/sites/default/files/2025-05/parkinsons-disease-hope-through-research.pdf"}]'::jsonb, now()
);


