) VALUES (
  'sidelka-oncology-spb-s-prozhivaniem-v-frunzenskiy', '/sidelka-oncology-spb-s-prozhivaniem-v-frunzenskiy', 'Онкология: Фрунзенский', 'Сиделка с проживанием при онкологическом заболевании в Фрунзенский районе (СПб)', 'Сиделка с проживанием Фрунзенский СПб - уход при Онкология', 'Уход с проживанием при онкологическом заболевании в Фрунзенский районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Фрунзенский районе мы выстраиваем маршрут ухода с проживанием при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Фрунзенский районе","points":["Учитываем логистику и доступность для семьи в Фрунзенский районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Фрунзенский районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для онкопациента с выраженной слабостью в Санкт-Петербурге","сиделка с проживанием при онкологическом заболевании в Фрунзенский районе","сиделка с проживанием СПб онкология спб","подбор сиделки при онкологическом заболевании фрунзенский районе","низкочастотный запрос: уход с проживанием онкология фрунзенский"]'::jsonb, '[{"question":"Работаете ли вы в Фрунзенский районе?","answer":"Да, мы принимаем заявки из Фрунзенский районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Фрунзенский районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-als-spb-kruglosutochno-v-tsentralnyy', '/sidelka-als-spb-kruglosutochno-v-tsentralnyy', 'БАС: Центральный', 'Сиделка круглосуточно при БАСе (боковом амиотрофическом склерозе) в Центральный районе (СПб)', 'Сиделка круглосуточно Центральный СПб - уход при БАС', 'Уход круглосуточно при БАСе (боковом амиотрофическом склерозе) в Центральный районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Центральный районе мы выстраиваем маршрут ухода круглосуточно при БАСе (боковом амиотрофическом склерозе).',
  '[{"heading":"Особенности ухода в Центральный районе","points":["Учитываем логистику и доступность для семьи в Центральный районе.","Основные риски в кейсах этого профиля: высокая нагрузка на семью, позиционирование, длительный уход.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Центральный районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для тяжелобольного пациента с нарастающей слабостью в Санкт-Петербурге","сиделка круглосуточно при БАСе (боковом амиотрофическом склерозе) в Центральный районе","круглосуточная сиделка СПб бас спб","подбор сиделки при БАСе (боковом амиотрофическом склерозе) центральный районе","низкочастотный запрос: уход круглосуточно бас центральный"]'::jsonb, '[{"question":"Работаете ли вы в Центральный районе?","answer":"Да, мы принимаем заявки из Центральный районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Центральный районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed/PMC: Caregiver burden in ALS (systematic review)","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC5784458/"},{"title":"PubMed: Coping strategies in ALS/FTD caregivers","url":"https://pubmed.ncbi.nlm.nih.gov/34937437/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-tracheostomy-spb-na-dom-v-kolomyagi', '/sidelka-tracheostomy-spb-na-dom-v-kolomyagi', 'Трахеостома: Коломяги', 'Сиделка на дому при трахеостоме в Коломяги районе (СПб)', 'Сиделка на дому Коломяги СПб - уход при Трахеостома', 'Уход на дому при трахеостоме в Коломяги районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Коломяги районе мы выстраиваем маршрут ухода на дому при трахеостоме.',
  '[{"heading":"Особенности ухода в Коломяги районе","points":["Учитываем логистику и доступность для семьи в Коломяги районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Коломяги районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пациента после стационара с трахеостомой в Санкт-Петербурге","сиделка на дому при трахеостоме в Коломяги районе","уход на дому СПб трахеостома спб","подбор сиделки при трахеостоме коломяги районе","низкочастотный запрос: уход на дому трахеостома коломяги"]'::jsonb, '[{"question":"Работаете ли вы в Коломяги районе?","answer":"Да, мы принимаем заявки из Коломяги районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Коломяги районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


