) VALUES (
  'sidelka-diabetes-spb-kruglosutochno-v-shuvalovo-ozerki', '/sidelka-diabetes-spb-kruglosutochno-v-shuvalovo-ozerki', 'Диабет: Шувалово-Озерки', 'Сиделка круглосуточно при сахарном диабете у пожилых в Шувалово-Озерки районе (СПб)', 'Сиделка круглосуточно Шувалово-Озерки СПб - уход при Диабет', 'Уход круглосуточно при сахарном диабете у пожилых в Шувалово-Озерки районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Шувалово-Озерки районе мы выстраиваем маршрут ухода круглосуточно при сахарном диабете у пожилых.',
  '[{"heading":"Особенности ухода в Шувалово-Озерки районе","points":["Учитываем логистику и доступность для семьи в Шувалово-Озерки районе.","Основные риски в кейсах этого профиля: режим питания, контроль самочувствия, профилактика падений.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Шувалово-Озерки районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с сопутствующими рисками в Санкт-Петербурге","сиделка круглосуточно при сахарном диабете у пожилых в Шувалово-Озерки районе","круглосуточная сиделка СПб диабет спб","подбор сиделки при сахарном диабете у пожилых шувалово-озерки районе","низкочастотный запрос: уход круглосуточно диабет шувалово-озерки"]'::jsonb, '[{"question":"Работаете ли вы в Шувалово-Озерки районе?","answer":"Да, мы принимаем заявки из Шувалово-Озерки районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Шувалово-Озерки районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Diabetes fact sheet","url":"https://www.who.int/news-room/fact-sheets/detail/diabetes"},{"title":"CDC: Helping friends and family with diabetes","url":"https://www.cdc.gov/diabetes/caring/index.html"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-fracture-spb-na-dom-v-ozero-dolgoe', '/sidelka-fracture-spb-na-dom-v-ozero-dolgoe', 'Перелом шейки бедра: Озеро Долгое', 'Сиделка на дому при переломе шейки бедра в Озеро Долгое районе (СПб)', 'Сиделка на дому Озеро Долгое СПб - уход при Перелом шейки бедра', 'Уход на дому при переломе шейки бедра в Озеро Долгое районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Озеро Долгое районе мы выстраиваем маршрут ухода на дому при переломе шейки бедра.',
  '[{"heading":"Особенности ухода в Озеро Долгое районе","points":["Учитываем логистику и доступность для семьи в Озеро Долгое районе.","Основные риски в кейсах этого профиля: безопасное перемещение, пролежни, реабилитационный режим.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Озеро Долгое районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для маломобильного пожилого пациента в Санкт-Петербурге","сиделка на дому при переломе шейки бедра в Озеро Долгое районе","уход на дому СПб перелом шейки бедра спб","подбор сиделки при переломе шейки бедра озеро долгое районе","низкочастотный запрос: уход на дому перелом шейки бедра озеро долгое"]'::jsonb, '[{"question":"Работаете ли вы в Озеро Долгое районе?","answer":"Да, мы принимаем заявки из Озеро Долгое районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Озеро Долгое районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-bedridden-spb-srochno-v-komendantskiy-aerodrom', '/sidelka-bedridden-spb-srochno-v-komendantskiy-aerodrom', 'Лежачий больной: Комендантский Аэродром', 'Сиделка срочно при уходе за лежачим больным в Комендантский Аэродром районе (СПб)', 'Сиделка срочно Комендантский Аэродром СПб - уход при Лежачий больной', 'Уход срочно при уходе за лежачим больным в Комендантский Аэродром районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Комендантский Аэродром районе мы выстраиваем маршрут ухода срочно при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Комендантский Аэродром районе","points":["Учитываем логистику и доступность для семьи в Комендантский Аэродром районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Комендантский Аэродром районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для лежачего подопечного с постоянной потребностью в помощи в Санкт-Петербурге","сиделка срочно при уходе за лежачим больным в Комендантский Аэродром районе","срочно сиделка СПб лежачий больной спб","подбор сиделки при уходе за лежачим больным комендантский аэродром районе","низкочастотный запрос: уход срочно лежачий больной комендантский аэродром"]'::jsonb, '[{"question":"Работаете ли вы в Комендантский Аэродром районе?","answer":"Да, мы принимаем заявки из Комендантский Аэродром районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Комендантский Аэродром районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-postop-spb-s-prozhivaniem-v-chernaya-rechka', '/sidelka-postop-spb-s-prozhivaniem-v-chernaya-rechka', 'После операции: Черная Речка', 'Сиделка с проживанием при восстановлении после операции в Черная Речка районе (СПб)', 'Сиделка с проживанием Черная Речка СПб - уход при После операции', 'Уход с проживанием при восстановлении после операции в Черная Речка районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Черная Речка районе мы выстраиваем маршрут ухода с проживанием при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Черная Речка районе","points":["Учитываем логистику и доступность для семьи в Черная Речка районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Черная Речка районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для подопечного после выписки из стационара в Санкт-Петербурге","сиделка с проживанием при восстановлении после операции в Черная Речка районе","сиделка с проживанием СПб после операции спб","подбор сиделки при восстановлении после операции черная речка районе","низкочастотный запрос: уход с проживанием после операции черная речка"]'::jsonb, '[{"question":"Работаете ли вы в Черная Речка районе?","answer":"Да, мы принимаем заявки из Черная Речка районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Черная Речка районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


