  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-nightcare-spb-na-dom-v-shushary', '/sidelka-nightcare-spb-na-dom-v-shushary', 'Ночной уход: Шушары', 'Сиделка на дому при сложном ночном уходе в Шушары районе (СПб)', 'Сиделка на дому Шушары СПб - уход при Ночной уход', 'Уход на дому при сложном ночном уходе в Шушары районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Шушары районе мы выстраиваем маршрут ухода на дому при сложном ночном уходе.',
  '[{"heading":"Особенности ухода в Шушары районе","points":["Учитываем логистику и доступность для семьи в Шушары районе.","Основные риски в кейсах этого профиля: бессонница, ночные подъемы, риск падений ночью.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Шушары районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для пожилого человека с ночной тревожностью в Санкт-Петербурге","сиделка на дому при сложном ночном уходе в Шушары районе","уход на дому СПб ночной уход спб","подбор сиделки при сложном ночном уходе шушары районе","низкочастотный запрос: уход на дому ночной уход шушары"]'::jsonb, '[{"question":"Работаете ли вы в Шушары районе?","answer":"Да, мы принимаем заявки из Шушары районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Шушары районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


