) VALUES (
  'sidelka-oncology-spb-srochno-v-avtovo', '/sidelka-oncology-spb-srochno-v-avtovo', 'Онкология: Автово', 'Сиделка срочно при онкологическом заболевании в Автово районе (СПб)', 'Сиделка срочно Автово СПб - уход при Онкология', 'Уход срочно при онкологическом заболевании в Автово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Автово районе мы выстраиваем маршрут ухода срочно при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Автово районе","points":["Учитываем логистику и доступность для семьи в Автово районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Автово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для онкопациента с выраженной слабостью в Санкт-Петербурге","сиделка срочно при онкологическом заболевании в Автово районе","срочно сиделка СПб онкология спб","подбор сиделки при онкологическом заболевании автово районе","низкочастотный запрос: уход срочно онкология автово"]'::jsonb, '[{"question":"Работаете ли вы в Автово районе?","answer":"Да, мы принимаем заявки из Автово районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Автово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
