) VALUES (
  'sidelka-als-spb-s-prozhivaniem-v-ulyanka', '/sidelka-als-spb-s-prozhivaniem-v-ulyanka', 'БАС: Ульянка', 'Сиделка с проживанием при БАСе (боковом амиотрофическом склерозе) в Ульянка районе (СПб)', 'Сиделка с проживанием Ульянка СПб - уход при БАС', 'Уход с проживанием при БАСе (боковом амиотрофическом склерозе) в Ульянка районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Ульянка районе мы выстраиваем маршрут ухода с проживанием при БАСе (боковом амиотрофическом склерозе).',
  '[{"heading":"Особенности ухода в Ульянка районе","points":["Учитываем логистику и доступность для семьи в Ульянка районе.","Основные риски в кейсах этого профиля: высокая нагрузка на семью, позиционирование, длительный уход.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ульянка районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для тяжелобольного пациента с нарастающей слабостью в Санкт-Петербурге","сиделка с проживанием при БАСе (боковом амиотрофическом склерозе) в Ульянка районе","сиделка с проживанием СПб бас спб","подбор сиделки при БАСе (боковом амиотрофическом склерозе) ульянка районе","низкочастотный запрос: уход с проживанием бас ульянка"]'::jsonb, '[{"question":"Работаете ли вы в Ульянка районе?","answer":"Да, мы принимаем заявки из Ульянка районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Ульянка районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed/PMC: Caregiver burden in ALS (systematic review)","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC5784458/"},{"title":"PubMed: Coping strategies in ALS/FTD caregivers","url":"https://pubmed.ncbi.nlm.nih.gov/34937437/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
