) VALUES (
  'sidelka-tracheostomy-spb-kruglosutochno-v-dachnoe', '/sidelka-tracheostomy-spb-kruglosutochno-v-dachnoe', 'Трахеостома: Дачное', 'Сиделка круглосуточно при трахеостоме в Дачное районе (СПб)', 'Сиделка круглосуточно Дачное СПб - уход при Трахеостома', 'Уход круглосуточно при трахеостоме в Дачное районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Дачное районе мы выстраиваем маршрут ухода круглосуточно при трахеостоме.',
  '[{"heading":"Особенности ухода в Дачное районе","points":["Учитываем логистику и доступность для семьи в Дачное районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Дачное районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пациента после стационара с трахеостомой в Санкт-Петербурге","сиделка круглосуточно при трахеостоме в Дачное районе","круглосуточная сиделка СПб трахеостома спб","подбор сиделки при трахеостоме дачное районе","низкочастотный запрос: уход круглосуточно трахеостома дачное"]'::jsonb, '[{"question":"Работаете ли вы в Дачное районе?","answer":"Да, мы принимаем заявки из Дачное районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Дачное районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
