) VALUES (
  'sidelka-gastrostomy-spb-na-dom-v-ligovo', '/sidelka-gastrostomy-spb-na-dom-v-ligovo', 'Гастростома: Лигово', 'Сиделка на дому при гастростоме в Лигово районе (СПб)', 'Сиделка на дому Лигово СПб - уход при Гастростома', 'Уход на дому при гастростоме в Лигово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Лигово районе мы выстраиваем маршрут ухода на дому при гастростоме.',
  '[{"heading":"Особенности ухода в Лигово районе","points":["Учитываем логистику и доступность для семьи в Лигово районе.","Основные риски в кейсах этого профиля: режим питания, уход за кожей, профилактика осложнений.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Лигово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для лежачего пациента с ограниченной подвижностью в Санкт-Петербурге","сиделка на дому при гастростоме в Лигово районе","уход на дому СПб гастростома спб","подбор сиделки при гастростоме лигово районе","низкочастотный запрос: уход на дому гастростома лигово"]'::jsonb, '[{"question":"Работаете ли вы в Лигово районе?","answer":"Да, мы принимаем заявки из Лигово районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Лигово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NHS: Find stoma support","url":"https://www.nhs.uk/service-search/other-health-services/stoma-support"},{"title":"Imperial NHS: Stoma care service","url":"https://www.imperial.nhs.uk/our-services/surgery/stoma-care"}]'::jsonb, now()
);


