) VALUES (
  'sidelka-diabetes-spb-s-prozhivaniem-v-strelna', '/sidelka-diabetes-spb-s-prozhivaniem-v-strelna', 'Диабет: Стрельна', 'Сиделка с проживанием при сахарном диабете у пожилых в Стрельна районе (СПб)', 'Сиделка с проживанием Стрельна СПб - уход при Диабет', 'Уход с проживанием при сахарном диабете у пожилых в Стрельна районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Стрельна районе мы выстраиваем маршрут ухода с проживанием при сахарном диабете у пожилых.',
  '[{"heading":"Особенности ухода в Стрельна районе","points":["Учитываем логистику и доступность для семьи в Стрельна районе.","Основные риски в кейсах этого профиля: режим питания, контроль самочувствия, профилактика падений.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Стрельна районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пожилого человека с сопутствующими рисками в Санкт-Петербурге","сиделка с проживанием при сахарном диабете у пожилых в Стрельна районе","сиделка с проживанием СПб диабет спб","подбор сиделки при сахарном диабете у пожилых стрельна районе","низкочастотный запрос: уход с проживанием диабет стрельна"]'::jsonb, '[{"question":"Работаете ли вы в Стрельна районе?","answer":"Да, мы принимаем заявки из Стрельна районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Стрельна районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Diabetes fact sheet","url":"https://www.who.int/news-room/fact-sheets/detail/diabetes"},{"title":"CDC: Helping friends and family with diabetes","url":"https://www.cdc.gov/diabetes/caring/index.html"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-fracture-spb-kruglosutochno-v-petergof', '/sidelka-fracture-spb-kruglosutochno-v-petergof', 'Перелом шейки бедра: Петергоф', 'Сиделка круглосуточно при переломе шейки бедра в Петергоф районе (СПб)', 'Сиделка круглосуточно Петергоф СПб - уход при Перелом шейки бедра', 'Уход круглосуточно при переломе шейки бедра в Петергоф районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Петергоф районе мы выстраиваем маршрут ухода круглосуточно при переломе шейки бедра.',
  '[{"heading":"Особенности ухода в Петергоф районе","points":["Учитываем логистику и доступность для семьи в Петергоф районе.","Основные риски в кейсах этого профиля: безопасное перемещение, пролежни, реабилитационный режим.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Петергоф районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для маломобильного пожилого пациента в Санкт-Петербурге","сиделка круглосуточно при переломе шейки бедра в Петергоф районе","круглосуточная сиделка СПб перелом шейки бедра спб","подбор сиделки при переломе шейки бедра петергоф районе","низкочастотный запрос: уход круглосуточно перелом шейки бедра петергоф"]'::jsonb, '[{"question":"Работаете ли вы в Петергоф районе?","answer":"Да, мы принимаем заявки из Петергоф районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Петергоф районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
