) VALUES (
  'sidelka-bedridden-spb-na-dom-v-lomonosov', '/sidelka-bedridden-spb-na-dom-v-lomonosov', 'Лежачий больной: Ломоносов', 'Сиделка на дому при уходе за лежачим больным в Ломоносов районе (СПб)', 'Сиделка на дому Ломоносов СПб - уход при Лежачий больной', 'Уход на дому при уходе за лежачим больным в Ломоносов районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Ломоносов районе мы выстраиваем маршрут ухода на дому при уходе за лежачим больным.',
  '[{"heading":"Особенности ухода в Ломоносов районе","points":["Учитываем логистику и доступность для семьи в Ломоносов районе.","Основные риски в кейсах этого профиля: гигиена, пролежни, повороты по графику.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Ломоносов районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для лежачего подопечного с постоянной потребностью в помощи в Санкт-Петербурге","сиделка на дому при уходе за лежачим больным в Ломоносов районе","уход на дому СПб лежачий больной спб","подбор сиделки при уходе за лежачим больным ломоносов районе","низкочастотный запрос: уход на дому лежачий больной ломоносов"]'::jsonb, '[{"question":"Работаете ли вы в Ломоносов районе?","answer":"Да, мы принимаем заявки из Ломоносов районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Ломоносов районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


