) VALUES (
  'sidelka-postop-spb-srochno-v-sestroretsk', '/sidelka-postop-spb-srochno-v-sestroretsk', 'После операции: Сестрорецк', 'Сиделка срочно при восстановлении после операции в Сестрорецк районе (СПб)', 'Сиделка срочно Сестрорецк СПб - уход при После операции', 'Уход срочно при восстановлении после операции в Сестрорецк районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Сестрорецк районе мы выстраиваем маршрут ухода срочно при восстановлении после операции.',
  '[{"heading":"Особенности ухода в Сестрорецк районе","points":["Учитываем логистику и доступность для семьи в Сестрорецк районе.","Основные риски в кейсах этого профиля: слабость, контроль режима, безопасность дома.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Сестрорецк районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для подопечного после выписки из стационара в Санкт-Петербурге","сиделка срочно при восстановлении после операции в Сестрорецк районе","срочно сиделка СПб после операции спб","подбор сиделки при восстановлении после операции сестрорецк районе","низкочастотный запрос: уход срочно после операции сестрорецк"]'::jsonb, '[{"question":"Работаете ли вы в Сестрорецк районе?","answer":"Да, мы принимаем заявки из Сестрорецк районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Сестрорецк районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"},{"title":"PubMed: Stroke rehabilitation in adults (guideline summary)","url":"https://pubmed.ncbi.nlm.nih.gov/38147522/"},{"title":"PubMed: Home-based training for stroke caregivers (RCT)","url":"https://pubmed.ncbi.nlm.nih.gov/25759177/"}]'::jsonb, now()
);


