) VALUES (
  'sidelka-nightcare-spb-kruglosutochno-v-pavlovsk', '/sidelka-nightcare-spb-kruglosutochno-v-pavlovsk', 'Ночной уход: Павловск', 'Сиделка круглосуточно при сложном ночном уходе в Павловск районе (СПб)', 'Сиделка круглосуточно Павловск СПб - уход при Ночной уход', 'Уход круглосуточно при сложном ночном уходе в Павловск районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Выстраиваем системный формат сопровождения с курацией и обратной связью. Для семей в Павловск районе мы выстраиваем маршрут ухода круглосуточно при сложном ночном уходе.',
  '[{"heading":"Особенности ухода в Павловск районе","points":["Учитываем логистику и доступность для семьи в Павловск районе.","Основные риски в кейсах этого профиля: бессонница, ночные подъемы, риск падений ночью.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного.","Уход строится на прогнозируемом режиме и контроле бытовых рисков."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Павловск районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка круглосуточно для пожилого человека с ночной тревожностью в Санкт-Петербурге","сиделка круглосуточно при сложном ночном уходе в Павловск районе","круглосуточная сиделка СПб ночной уход спб","подбор сиделки при сложном ночном уходе павловск районе","низкочастотный запрос: уход круглосуточно ночной уход павловск"]'::jsonb, '[{"question":"Работаете ли вы в Павловск районе?","answer":"Да, мы принимаем заявки из Павловск районе и подбираем специалиста под профиль диагноза и формат круглосуточно."},{"question":"Можно ли подобрать сиделку срочно в Павловск районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"WHO Fact Sheet: Dementia","url":"https://www.who.int/news-room/fact-sheets/dementia"},{"title":"National Institute on Aging: Alzheimer’s Caregiving","url":"https://www.nia.nih.gov/health/alzheimers-and-dementia/caregiving"},{"title":"WHO: Integrated Care for Older People (ICOPE)","url":"https://www.who.int/publications-detail-redirect/9789241550109"},{"title":"NIA: Cognitive health and older adults","url":"https://www.nia.nih.gov/health/brain-health/cognitive-health-and-older-adults"}]'::jsonb, now()
);


