) VALUES (
  'sidelka-oncology-spb-na-dom-v-okkervil', '/sidelka-oncology-spb-na-dom-v-okkervil', 'Онкология: Оккервиль', 'Сиделка на дому при онкологическом заболевании в Оккервиль районе (СПб)', 'Сиделка на дому Оккервиль СПб - уход при Онкология', 'Уход на дому при онкологическом заболевании в Оккервиль районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Мы подбираем сиделку под конкретный клинический сценарий, а не по формальному резюме. Для семей в Оккервиль районе мы выстраиваем маршрут ухода на дому при онкологическом заболевании.',
  '[{"heading":"Особенности ухода в Оккервиль районе","points":["Учитываем логистику и доступность для семьи в Оккервиль районе.","Основные риски в кейсах этого профиля: боль и утомляемость, снижение аппетита, поддержка семьи.","Мы фиксируем наблюдения и передаем семье понятные отчеты.","План действий заранее согласуется с семьей и корректируется по состоянию подопечного."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Оккервиль районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка на дому для онкопациента с выраженной слабостью в Санкт-Петербурге","сиделка на дому при онкологическом заболевании в Оккервиль районе","уход на дому СПб онкология спб","подбор сиделки при онкологическом заболевании оккервиль районе","низкочастотный запрос: уход на дому онкология оккервиль"]'::jsonb, '[{"question":"Работаете ли вы в Оккервиль районе?","answer":"Да, мы принимаем заявки из Оккервиль районе и подбираем специалиста под профиль диагноза и формат на дому."},{"question":"Можно ли подобрать сиделку срочно в Оккервиль районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"NCI: Family caregiving for cancer patients","url":"https://www.cancer.gov/about-cancer/coping/family-friends/family-caregivers-pdq"},{"title":"WHO: Palliative care","url":"https://www.who.int/news-room/fact-sheets/detail/palliative-care"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-als-spb-srochno-v-grazhdanka', '/sidelka-als-spb-srochno-v-grazhdanka', 'БАС: Гражданка', 'Сиделка срочно при БАСе (боковом амиотрофическом склерозе) в Гражданка районе (СПб)', 'Сиделка срочно Гражданка СПб - уход при БАС', 'Уход срочно при БАСе (боковом амиотрофическом склерозе) в Гражданка районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Ставим в приоритет безопасность подопечного и спокойствие семьи с первого дня. Для семей в Гражданка районе мы выстраиваем маршрут ухода срочно при БАСе (боковом амиотрофическом склерозе).',
  '[{"heading":"Особенности ухода в Гражданка районе","points":["Учитываем логистику и доступность для семьи в Гражданка районе.","Основные риски в кейсах этого профиля: высокая нагрузка на семью, позиционирование, длительный уход.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома.","Мы фиксируем наблюдения и передаем семье понятные отчеты."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Гражданка районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка срочно для тяжелобольного пациента с нарастающей слабостью в Санкт-Петербурге","сиделка срочно при БАСе (боковом амиотрофическом склерозе) в Гражданка районе","срочно сиделка СПб бас спб","подбор сиделки при БАСе (боковом амиотрофическом склерозе) гражданка районе","низкочастотный запрос: уход срочно бас гражданка"]'::jsonb, '[{"question":"Работаете ли вы в Гражданка районе?","answer":"Да, мы принимаем заявки из Гражданка районе и подбираем специалиста под профиль диагноза и формат срочно."},{"question":"Можно ли подобрать сиделку срочно в Гражданка районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed/PMC: Caregiver burden in ALS (systematic review)","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC5784458/"},{"title":"PubMed: Coping strategies in ALS/FTD caregivers","url":"https://pubmed.ncbi.nlm.nih.gov/34937437/"}]'::jsonb, now()
);


INSERT INTO pc_seo_pages (
  slug, path, nav_label, title, meta_title, meta_description, added_at, lead,
  sections, low_frequency_queries, faq, scientific_links, updated_at
) VALUES (
  'sidelka-tracheostomy-spb-s-prozhivaniem-v-polyustrovo', '/sidelka-tracheostomy-spb-s-prozhivaniem-v-polyustrovo', 'Трахеостома: Полюстрово', 'Сиделка с проживанием при трахеостоме в Полюстрово районе (СПб)', 'Сиделка с проживанием Полюстрово СПб - уход при Трахеостома', 'Уход с проживанием при трахеостоме в Полюстрово районе: НЧ-запросы, научные источники, обучение персонала и FAQ по району.', '2026-03-27', 'Организуем уход так, чтобы снизить ежедневную нагрузку на близких. Для семей в Полюстрово районе мы выстраиваем маршрут ухода с проживанием при трахеостоме.',
  '[{"heading":"Особенности ухода в Полюстрово районе","points":["Учитываем логистику и доступность для семьи в Полюстрово районе.","Основные риски в кейсах этого профиля: дыхательный комфорт, гигиена, круглосуточное наблюдение.","Уход строится на прогнозируемом режиме и контроле бытовых рисков.","Ключевая цель - стабильность и снижение вероятности экстренных ситуаций дома."]},{"heading":"Обучение и контроль персонала","points":["Внутренний чек-лист запуска ухода: состояние подопечного, факторы риска, эскалация экстренных сценариев.","Инструктаж по коммуникации с семьей: ежедневный отчет, передача наблюдений, фиксация динамики.","Контроль режима: питание, прием лекарств по назначениям врача, гигиена, сон, профилактика падений и пролежней.","Кураторское сопровождение после выхода сиделки и плановая замена при необходимости."]},{"heading":"Маршрут для семьи по району","points":["Фиксируем график ухода и контактное окно для родственников в Полюстрово районе.","Согласовываем резервный план на случай экстренного ухудшения состояния.","Подключаем куратора на старте и в точках изменения клинической картины.","Проводим регулярную сверку качества ухода по чек-листу."]}]'::jsonb, '["сиделка с проживанием для пациента после стационара с трахеостомой в Санкт-Петербурге","сиделка с проживанием при трахеостоме в Полюстрово районе","сиделка с проживанием СПб трахеостома спб","подбор сиделки при трахеостоме полюстрово районе","низкочастотный запрос: уход с проживанием трахеостома полюстрово"]'::jsonb, '[{"question":"Работаете ли вы в Полюстрово районе?","answer":"Да, мы принимаем заявки из Полюстрово районе и подбираем специалиста под профиль диагноза и формат с проживанием."},{"question":"Можно ли подобрать сиделку срочно в Полюстрово районе?","answer":"Да, в срочных кейсах запускаем подбор в день обращения и первично закрываем задачи безопасности."},{"question":"Как учитываются особенности маршрута и графика семьи?","answer":"Перед стартом фиксируем окно посещений родственников, правила связи и график отчетности, чтобы уход был прозрачным."}]'::jsonb, '[{"title":"PubMed: Tracheostomy home care and caregiver burden","url":"https://pubmed.ncbi.nlm.nih.gov/30986200/"},{"title":"PubMed: Tracheostomy patient/caregiver experience review","url":"https://pubmed.ncbi.nlm.nih.gov/28914429/"}]'::jsonb, now()
);


